// --- Execution Limits (Anti-Runaway Circuit Breakers) ---
const SAFETY_LIMITS = {
  MAX_TURNS: 500,
  MAX_SCROLL_ITERATIONS: 100,
  MAX_EXTRACTION_TIME_MS: 60_000,
  MAX_CLIPBOARD_WAIT_MS: 2_000,
  MAX_SINGLE_TURN_SIZE: 100_000,
  SCROLL_STABILITY_THRESHOLD: 3,
  CLIPBOARD_READ_DELAY_MS: 175,
  SCROLL_STEP_DELAY_MS: 300,
  HOVER_SETTLE_MS: 50,
};

const SCHEMA_VERSION = '1.0';
const EXTENSION_VERSION = '0.9.7';

// --- Platform Detection ---
function detectPlatform() {
  const host = window.location.hostname;
  const path = window.location.pathname;

  if (host === 'claude.ai') return 'claude';
  if (host === 'chatgpt.com' || host === 'chat.openai.com') return 'chatgpt';
  if (host === 'gemini.google.com') return 'gemini';
  if (host === 'grok.com') return 'grok';
  if (host === 'x.com' && path.startsWith('/i/grok')) return 'grok-x';
  if (host === 'perplexity.ai' || host === 'www.perplexity.ai') return 'perplexity';
  return null;
}

function platformToDisplayName(platform) {
  const names = {
    claude: 'claude.ai',
    chatgpt: 'chatgpt.com',
    gemini: 'gemini.google.com',
    grok: 'grok.com',
    'grok-x': 'x.com/i/grok',
    perplexity: 'perplexity.ai',
  };
  return names[platform] || platform;
}

// --- Shared DOM Utilities ---

function wait(ms) {
  return new Promise((resolve) => setTimeout(resolve, ms));
}

/**
 * Wait for conversation DOM to be ready before extraction.
 * Polls for platform-specific conversation elements.
 * Returns { ready: true } when found, or { ready: false, error: 'timeout' } after timeout.
 */
async function waitForConversationReady(options = {}) {
  const timeoutMs = options.timeout || 15000;
  const pollIntervalMs = options.pollInterval || 400;
  const platform = detectPlatform();
  
  if (!platform) {
    return { ready: false, error: 'Not on a supported platform' };
  }

  const selectors = {
    chatgpt:
      'article[data-testid^="conversation-turn-"], [data-testid^="conversation-turn-"], [data-message-author-role="user"], [data-message-author-role="assistant"]',
    claude: '[data-testid="user-message"], .font-claude-message',
    gemini: 'user-query, model-response',
    grok: '[class*="message"], [data-testid*="message"]',
    'grok-x': '[data-testid*="message"], [class*="message"]',
    perplexity: 'button[aria-label="Copy query"], button[data-testid="copy-query-button"], .prose.text-pretty',
  };

  const selector = selectors[platform];
  if (!selector) {
    return { ready: false, error: `No selector for platform: ${platform}` };
  }

  const startTime = Date.now();
  
  while (Date.now() - startTime < timeoutMs) {
    const element = document.querySelector(selector);
    if (element) {
      console.log(`[ChatVault] Conversation ready after ${Date.now() - startTime}ms`);
      return { ready: true, waitedMs: Date.now() - startTime };
    }
    await wait(pollIntervalMs);
  }

  console.warn(`[ChatVault] Conversation not ready after ${timeoutMs}ms timeout`);
  return { ready: false, error: 'timeout', waitedMs: timeoutMs };
}

/**
 * Test if clipboard read access is available.
 * Some browsers block navigator.clipboard.readText() in extension contexts.
 */
async function testClipboardAccess() {
  try {
    await navigator.clipboard.readText();
    return true;
  } catch {
    return false;
  }
}

/**
 * Fuzzy button finder — resilient to selector changes.
 * Searches by aria-label, title, data-testid, and tooltip text.
 */
function findActionButton(container, intent) {
  // intent: 'copy', 'edit', 'copy text', 'copy prompt', etc.
  const intents = Array.isArray(intent) ? intent : [intent];

  for (const label of intents) {
    const strategies = [
      // Strategy 1: exact aria-label (most stable — user-facing)
      () => container.querySelector(`button[aria-label="${label}"]`),
      // Strategy 2: case-insensitive aria-label contains
      () => container.querySelector(`button[aria-label*="${label}" i]`),
      // Strategy 3: data-testid containing intent
      () => container.querySelector(`button[data-testid*="${label.toLowerCase().replace(/\s+/g, '-')}"]`),
      // Strategy 4: title attribute
      () => container.querySelector(`button[title*="${label}" i]`),
      // Strategy 5: mattooltip (Angular Material)
      () => container.querySelector(`button[mattooltip*="${label}" i]`),
    ];

    for (const strategy of strategies) {
      try {
        const result = strategy();
        if (result) return result;
      } catch {
        // Selector syntax error — skip
      }
    }
  }
  return null;
}

/**
 * Click a copy button and read the resulting clipboard content.
 * Returns the clipboard text, or null on failure.
 */
async function clickCopyAndRead(button) {
  if (!button) return null;

  try {
    // Snapshot current clipboard to detect change
    let previous = '';
    try {
      previous = await navigator.clipboard.readText();
    } catch {
      // Clipboard empty or inaccessible — ok, we'll still try
    }

    button.click();
    await wait(SAFETY_LIMITS.CLIPBOARD_READ_DELAY_MS);

    const content = await navigator.clipboard.readText();

    // Verify we got something (and ideally something different)
    if (content && content.length > 0) {
      return content;
    }
    return null;
  } catch {
    return null;
  }
}

/**
 * Scroll a container to load all lazy-loaded content.
 * Returns the number of scroll iterations performed.
 */
async function scrollToLoadAll(scrollContainer, countSource, startTime) {
  const getCount =
    typeof countSource === 'function'
      ? countSource
      : () => document.querySelectorAll(countSource).length;

  let previousCount = 0;
  let stableIterations = 0;
  let scrollIterations = 0;

  const initialScrollHeight = scrollContainer.scrollHeight;
  console.log(`[Chat Archive] Scroll: Initial height=${initialScrollHeight}, clientHeight=${scrollContainer.clientHeight}`);
  
  scrollContainer.scrollTop = 0;
  await wait(500);

  while (
    stableIterations < SAFETY_LIMITS.SCROLL_STABILITY_THRESHOLD &&
    scrollIterations < SAFETY_LIMITS.MAX_SCROLL_ITERATIONS
  ) {
    if (startTime && Date.now() - startTime > SAFETY_LIMITS.MAX_EXTRACTION_TIME_MS) break;

    const currentCount = getCount();
    console.log(`[Chat Archive] Scroll iteration ${scrollIterations}: found ${currentCount} elements (prev: ${previousCount}), stable: ${stableIterations}`);
    
    if (currentCount === previousCount) {
      stableIterations++;
    } else {
      stableIterations = 0;
      previousCount = currentCount;
    }

    const scrollAmount = scrollContainer.clientHeight * 0.8;
    console.log(`[Chat Archive] Scrolling by ${scrollAmount}px, current scrollTop: ${scrollContainer.scrollTop}`);
    scrollContainer.scrollBy(0, scrollAmount);
    await wait(SAFETY_LIMITS.SCROLL_STEP_DELAY_MS);
    scrollIterations++;
  }

  // Scroll back to top for clean state
  scrollContainer.scrollTop = 0;
  await wait(200);

  console.log(`[Chat Archive] Scroll complete: ${previousCount} elements after ${scrollIterations} scrolls`);
  return scrollIterations;
}

/**
 * Find the scrollable ancestor of a given element.
 */
function findScrollableAncestor(element) {
  let parent = element.parentElement;
  while (parent) {
    const style = window.getComputedStyle(parent);
    if (style.overflowY === 'scroll' || style.overflowY === 'auto') {
      return parent;
    }
    parent = parent.parentElement;
  }
  return null;
}

/**
 * Flag a turn for size if needed, mutates the turn object.
 */
function flagIfOversized(turn) {
  if (turn.content && turn.content.length > SAFETY_LIMITS.MAX_SINGLE_TURN_SIZE) {
    turn.flagged = true;
    turn.flagReason = 'Content exceeds 100KB';
  }
  return turn;
}


// --- src/extractors/claude.js ---
// =============================================================================
// Chat Archive — Claude.ai Extractor (Pass 0 + Direct Text Fallback)
// =============================================================================
// Architecture: Appendix C
// Turn container: div[data-test-render-count] wraps user+assistant pair
// Copy buttons: button[data-testid="action-bar-copy"] on both roles
// Role signals: [data-testid="user-message"] (user), [data-is-streaming] (assistant)

async function extractClaudeConversation() {
  const startTime = Date.now();
  const turns = [];
  const errors = [];

  // 1. Find scroll container
  const scrollContainer = findClaudeScrollContainer();
  if (!scrollContainer) {
    return { turns: [], errors: ['Scroll container not found'], partial: true };
  }

  // 2. Load all turns via scrolling
  await scrollToLoadAll(scrollContainer, '[data-test-render-count]', startTime);

  // 3. Get turn pair containers
  const turnContainers = document.querySelectorAll('[data-test-render-count]');
  console.log(`[Chat Archive] Claude: Found ${turnContainers.length} turn containers`);

  if (turnContainers.length === 0) {
    return { turns: [], errors: ['No turn containers found'], partial: true };
  }

  // 4. Test clipboard access
  const hasClipboard = await testClipboardAccess();
  console.log(`[Chat Archive] Claude: Clipboard access: ${hasClipboard}`);

  // 5. Extract each turn pair
  for (let i = 0; i < turnContainers.length; i++) {
    if (Date.now() - startTime > SAFETY_LIMITS.MAX_EXTRACTION_TIME_MS) {
      errors.push(`Extraction timed out after ${SAFETY_LIMITS.MAX_EXTRACTION_TIME_MS}ms`);
      break;
    }
    if (turns.length >= SAFETY_LIMITS.MAX_TURNS) {
      errors.push(`Hit maximum turn limit (${SAFETY_LIMITS.MAX_TURNS})`);
      break;
    }

    const container = turnContainers[i];

    try {
      // Scroll into view to ensure content is rendered
      container.scrollIntoView({ behavior: 'instant', block: 'center' });
      await wait(150);

      // Extract user turn
      const userTurn = await extractClaudeTurn(container, 'user', hasClipboard);
      if (userTurn) turns.push(flagIfOversized(userTurn));

      // Extract assistant turn
      const assistantTurn = await extractClaudeTurn(container, 'assistant', hasClipboard);
      if (assistantTurn) turns.push(flagIfOversized(assistantTurn));
    } catch (err) {
      errors.push(`Error extracting container ${i}: ${err.message}`);
      console.warn(`[Chat Archive] Claude: Error on container ${i}:`, err);
    }
  }

  console.log(`[Chat Archive] Claude: Extracted ${turns.length} turns, ${errors.length} errors`);
  return { turns, errors, partial: errors.length > 0 };
}

/**
 * Extract a single turn (user or assistant) from a turn-pair container.
 * Pass 0: Try copy button → clipboard. Fallback: direct text extraction.
 */
async function extractClaudeTurn(container, role, hasClipboard) {
  // Determine which sub-element to target
  const roleSelector = role === 'user'
    ? '[data-testid="user-message"]'
    : '[data-is-streaming]';

  // Fallback role selector
  const fallbackSelector = role === 'user'
    ? '.font-user-message'
    : '.font-claude-response';

  const roleElement = container.querySelector(roleSelector)
    || container.querySelector(fallbackSelector);

  if (!roleElement) return null;

  // Find the nearest group container (for hover-triggering copy button visibility)
  const groupContainer = roleElement.closest('.group') || roleElement;

  let content = null;
  let extractionMethod = 'direct';

  // --- Pass 0: Clipboard via copy button ---
  if (hasClipboard) {
    try {
      // Trigger hover to ensure button is interactable
      groupContainer.dispatchEvent(new MouseEvent('mouseenter', { bubbles: true }));
      await wait(SAFETY_LIMITS.HOVER_SETTLE_MS);

      // Find copy button within this turn's group
      // Claude uses data-testid="action-bar-copy" — but each turn-pair has multiple
      // We need the copy button closest to our role element
      const copyButton = findClaudeCopyButton(groupContainer, container, role);

      if (copyButton) {
        const clipboardContent = await clickCopyAndRead(copyButton);
        if (clipboardContent && clipboardContent.trim().length > 0) {
          content = clipboardContent;
          extractionMethod = 'clipboard';
        }
      }

      groupContainer.dispatchEvent(new MouseEvent('mouseleave', { bubbles: true }));
    } catch (err) {
      console.warn(`[Chat Archive] Claude: Clipboard extraction failed for ${role}:`, err);
    }
  }

  // --- Fallback: Direct text extraction ---
  if (!content) {
    content = extractClaudeDirectText(container, role);
    extractionMethod = 'direct';
  }

  if (!content || content.trim().length === 0) return null;

  // Timestamp: prefer machine datetime (Claude often shows "Apr 3" without year in UI → Date.parse → 2001).
  let timestamp;
  const timeEl = container.querySelector('time[datetime]');
  if (timeEl) {
    const dt = timeEl.getAttribute('datetime');
    if (dt && dt.trim()) timestamp = dt.trim();
  }
  if (!timestamp) {
    const timestampEl = container.querySelector('span.text-text-500.text-xs');
    timestamp = timestampEl?.textContent?.trim() || undefined;
  }

  return {
    role,
    content: content.trim(),
    timestamp,
    extractionMethod,
    confidence: 0.95,
    classificationSource: 'structural',
  };
}

/**
 * Find the correct copy button for a specific role within a turn-pair container.
 * Each data-test-render-count container has TWO groups (user + assistant),
 * each with their own action bar and copy button.
 */
function findClaudeCopyButton(groupContainer, pairContainer, role) {
  // Try within the immediate group first
  let btn = groupContainer.querySelector('button[data-testid="action-bar-copy"]');
  if (btn) return btn;

  btn = findActionButton(groupContainer, ['Copy']);
  if (btn) return btn;

  // If group didn't have it, search all copy buttons in the pair container
  // and match by proximity to the role element
  const allCopyBtns = pairContainer.querySelectorAll('button[data-testid="action-bar-copy"]');
  if (allCopyBtns.length === 0) return null;

  if (allCopyBtns.length === 1) return allCopyBtns[0];

  // Multiple copy buttons — pick by position:
  // First copy button belongs to user, second to assistant
  if (role === 'user') return allCopyBtns[0];
  if (role === 'assistant') return allCopyBtns[allCopyBtns.length - 1];

  return allCopyBtns[0];
}

/**
 * Direct text extraction fallback for Claude.
 */
function extractClaudeDirectText(container, role) {
  if (role === 'user') {
    const el = container.querySelector('[data-testid="user-message"]');
    return el?.textContent?.trim() || '';
  } else {
    // Prefer .standard-markdown within .font-claude-response
    const markdown = container.querySelector('.font-claude-response .standard-markdown');
    if (markdown) return markdown.textContent?.trim() || '';

    const response = container.querySelector('.font-claude-response');
    if (response) return response.textContent?.trim() || '';

    const streaming = container.querySelector('[data-is-streaming]');
    return streaming?.textContent?.trim() || '';
  }
}

/**
 * Find Claude's scrollable chat container.
 */
function findClaudeScrollContainer() {
  const strategies = [
    () => document.querySelector('.overflow-y-scroll.overflow-x-hidden.pt-6.flex-1'),
    () => {
      const scrollables = document.querySelectorAll('[class*="overflow-y-scroll"]');
      for (const el of scrollables) {
        if (el.querySelector('[data-test-render-count]')) return el;
      }
      return null;
    },
    () => {
      const firstTurn = document.querySelector('[data-test-render-count]');
      return firstTurn ? findScrollableAncestor(firstTurn) : null;
    },
  ];

  for (const strategy of strategies) {
    const result = strategy();
    if (result) return result;
  }
  return null;
}


// --- src/extractors/chatgpt.js ---
// =============================================================================
// Chat Archive — ChatGPT Extractor (Pass 0 + Direct Text Fallback)
// =============================================================================
// Architecture: Appendix E
// Turn container: article[data-testid="conversation-turn-{N}"] — one per turn (flat)
// Copy button: button[data-testid="copy-turn-action-button"] on both roles
// Role signals: data-turn="user"|"assistant" on <article> (0.99)
//               data-message-author-role="user"|"assistant" (0.99)
//
// Newer ChatGPT web builds often omit article[data-testid^="conversation-turn-"] and
// expose flat [data-message-author-role] nodes instead — we support both.

const CHATGPT_MESSAGE_ROOT_SEL =
  '[data-message-author-role="user"], [data-message-author-role="assistant"]';

function findChatGPTMessageRootElements() {
  const candidates = document.querySelectorAll(CHATGPT_MESSAGE_ROOT_SEL);
  const roots = [];
  candidates.forEach((el) => {
    const parentMsg = el.parentElement?.closest(CHATGPT_MESSAGE_ROOT_SEL);
    if (parentMsg) return;
    roots.push(el);
  });
  return roots;
}

/** Turn containers: legacy <article> turns, or any conversation-turn testid, or message-role roots. */
function getChatGPTTurnContainerNodes() {
  const articles = document.querySelectorAll('article[data-testid^="conversation-turn-"]');
  if (articles.length > 0) return Array.from(articles);
  const byTestid = document.querySelectorAll('[data-testid^="conversation-turn-"]');
  if (byTestid.length > 0) return Array.from(byTestid);
  const msgRoots = findChatGPTMessageRootElements();
  if (msgRoots.length > 0) return msgRoots;
  const looseArticles = Array.from(document.querySelectorAll('main article, [class*="react-scroll"] article')).filter(
    (a) =>
      a.querySelector(
        '[data-message-author-role="user"], [data-message-author-role="assistant"], [data-message-content]'
      )
  );
  return looseArticles;
}

async function extractChatGPTConversation() {
  const startTime = Date.now();
  const turns = [];
  const errors = [];

  const scrollContainer = findChatGPTScrollContainer();
  if (!scrollContainer) {
    return { turns: [], errors: ['Scroll container not found'], partial: true };
  }

  await scrollToLoadAll(
    scrollContainer,
    () => getChatGPTTurnContainerNodes().length,
    startTime
  );

  const finalContainers = getChatGPTTurnContainerNodes();
  console.log(`[Chat Archive] ChatGPT: Found ${finalContainers.length} turn containers`);

  if (finalContainers.length === 0) {
    return {
      turns: [],
      errors: ['No conversation messages found (UI may have changed)'],
      partial: true,
    };
  }

  const hasClipboard = false;

  for (let i = 0; i < finalContainers.length; i++) {
    if (Date.now() - startTime > SAFETY_LIMITS.MAX_EXTRACTION_TIME_MS) {
      errors.push(`Extraction timed out after ${SAFETY_LIMITS.MAX_EXTRACTION_TIME_MS}ms`);
      break;
    }
    if (turns.length >= SAFETY_LIMITS.MAX_TURNS) {
      errors.push(`Hit maximum turn limit (${SAFETY_LIMITS.MAX_TURNS})`);
      break;
    }

    const container = finalContainers[i];

    try {
      container.scrollIntoView({ behavior: 'instant', block: 'center' });
      await wait(150);

      const turn = await extractChatGPTTurn(container, hasClipboard, i + 1);
      if (turn) turns.push(flagIfOversized(turn));
    } catch (err) {
      errors.push(`Error extracting turn ${i}: ${err.message}`);
      console.warn(`[Chat Archive] ChatGPT: Error on turn ${i}:`, err);
    }
  }

  console.log(`[Chat Archive] ChatGPT: Extracted ${turns.length} turns, ${errors.length} errors`);
  return { turns, errors, partial: errors.length > 0 };
}

async function extractChatGPTTurn(container, hasClipboard, sequentialTurnNumber) {
  let role = container.getAttribute('data-message-author-role');
  if (!role) role = container.getAttribute('data-turn');

  if (!role) {
    const msgDiv = container.querySelector('[data-message-author-role]');
    role = msgDiv?.getAttribute('data-message-author-role');
  }

  if (!role) {
    const h5 = container.querySelector('h5.sr-only');
    const h6 = container.querySelector('h6.sr-only');
    if (h5 && h5.textContent?.includes('You said')) role = 'user';
    else if (h6 && h6.textContent?.includes('ChatGPT said')) role = 'assistant';
  }

  if (role !== 'user' && role !== 'assistant') return null;

  const testId = container.getAttribute('data-testid') || '';
  let turnNumber = parseInt(testId.replace('conversation-turn-', ''), 10) || 0;
  if (!turnNumber && sequentialTurnNumber) turnNumber = sequentialTurnNumber;

  const turnId = container.getAttribute('data-turn-id') || '';
  const msgDiv = container.matches?.('[data-message-author-role]')
    ? container
    : container.querySelector('[data-message-author-role]');
  const modelSlug = msgDiv?.getAttribute('data-message-model-slug') || undefined;

  let content = null;
  let extractionMethod = 'direct';

  if (hasClipboard) {
    try {
      const copyBtn = container.querySelector('button[data-testid="copy-turn-action-button"]');
      if (!copyBtn) {
        const fallback = findActionButton(container, ['Copy']);
        if (fallback) {
          const clipContent = await clickCopyAndRead(fallback);
          if (clipContent && clipContent.trim().length > 0) {
            content = clipContent;
            extractionMethod = 'clipboard';
          }
        }
      } else {
        const clipContent = await clickCopyAndRead(copyBtn);
        if (clipContent && clipContent.trim().length > 0) {
          content = clipContent;
          extractionMethod = 'clipboard';
        }
      }
    } catch (err) {
      console.warn(`[Chat Archive] ChatGPT: Clipboard failed for turn ${turnNumber}:`, err);
    }
  }

  if (!content) {
    content = extractChatGPTDirectText(container, role);
    extractionMethod = 'direct';
  }

  if (!content || content.trim().length === 0) return null;

  let timestamp;
  const timeEl = container.querySelector('time[datetime]');
  if (timeEl) {
    const dt = timeEl.getAttribute('datetime');
    if (dt && dt.trim()) timestamp = dt.trim();
  }

  return {
    role,
    content: content.trim(),
    turnNumber,
    turnId,
    modelSlug,
    extractionMethod,
    confidence: 0.99,
    classificationSource: 'structural',
    timestamp,
  };
}

function extractChatGPTDirectText(container, role) {
  const msgContent = container.querySelector('[data-message-content]');
  if (msgContent) {
    const t = msgContent.textContent?.trim();
    if (t) return t;
  }

  if (role === 'user') {
    const el = container.querySelector('.whitespace-pre-wrap');
    if (el?.textContent?.trim()) return el.textContent.trim();
  }

  const markdown = container.querySelector('.markdown.prose') || container.querySelector('.markdown');
  if (markdown?.textContent?.trim()) return markdown.textContent.trim();

  const roleDiv = container.querySelector(`[data-message-author-role="${role}"]`);
  if (roleDiv?.textContent?.trim()) return roleDiv.textContent.trim();

  return container.textContent?.trim() || '';
}

function findChatGPTScrollContainer() {
  const firstTurn = document.querySelector(
    'article[data-testid^="conversation-turn-"], [data-testid^="conversation-turn-"], [data-message-author-role="user"], [data-message-author-role="assistant"]'
  );

  const strategies = [
    () => document.querySelector('[data-scroll-root]'),
    () => (firstTurn ? findScrollableAncestor(firstTurn) : null),
    () => document.querySelector('main [class*="overflow-y-auto"]'),
    () => {
      const main = document.querySelector('main');
      if (!main) return null;
      const last = main.querySelector('[data-message-author-role], article');
      return last ? findScrollableAncestor(last) : findScrollableAncestor(main);
    },
  ];

  for (const strategy of strategies) {
    const result = strategy();
    if (result) return result;
  }
  return null;
}

// -----------------------------------------------------------------------------
// ChatGPT — Attachments (uploads + assistant file links) for download
// -----------------------------------------------------------------------------
// Collects same-origin / OpenAI CDN URLs visible in the conversation DOM after
// full scroll. blob: links are skipped (not readable from the content script).
// -----------------------------------------------------------------------------

/**
 * *.oaiusercontent.com hosts both real chat uploads AND UI (avatars, icons, thumbnails).
 * Only treat as a downloadable attachment when the URL looks like a file payload, not chrome.
 */
function isOaiUserContentChatAttachmentUrl(u) {
  const pathLower = u.pathname.toLowerCase();
  const searchLower = (u.search || '').toLowerCase();
  const blob = pathLower + searchLower;
  if (/avatar|favicon|emoji|\/icon|\/logo|badge|placeholder|webpack|\/static\/|\/assets\/|sprite|thumbnail/i.test(blob)) {
    return false;
  }
  const w = parseInt(u.searchParams.get('w') || '0', 10);
  const h = parseInt(u.searchParams.get('h') || '0', 10);
  if (w > 0 && h > 0 && w <= 128 && h <= 128 && !u.searchParams.get('rscd')) {
    return false;
  }
  if (u.searchParams.get('rscd')) return true;
  const idq = u.searchParams.get('id') || '';
  if (idq.startsWith('file-')) return true;
  return false;
}

function isLikelyChatGPTFileUrl(absUrl, options) {
  const opts = options || {};
  let u;
  try {
    u = new URL(absUrl);
  } catch {
    return false;
  }
  if (u.protocol === 'blob:') return true;
  if (u.protocol !== 'https:') return false;
  const host = u.hostname.toLowerCase();
  const onChat =
    host === 'chatgpt.com' ||
    host === 'www.chatgpt.com' ||
    host === 'chat.openai.com';
  const onOpenAIAsset = host.endsWith('.oaiusercontent.com');
  if (!onChat && !onOpenAIAsset) return false;

  const path = u.pathname;
  const pathLower = path.toLowerCase();

  if (onChat) {
    if (/^\/c\/[^/]+\/?$/.test(path)) return false;
    if (pathLower.startsWith('/g/')) return false;
    if (pathLower.includes('/auth/') || pathLower.includes('/accounts/')) return false;
  }

  if (onOpenAIAsset) {
    if (isOaiUserContentChatAttachmentUrl(u)) return true;
    if (opts.allowLooseOaiImage && opts.element) {
      const inUser = opts.element.closest('[data-message-author-role="user"]');
      if (inUser && /\.(png|jpe?g|gif|webp|svg|heic)(\?|#|$)/i.test(path)) return true;
    }
    return false;
  }

  if (/\.(pdf|zip|csv|tsv|xlsx?|xls|docx?|doc|pptx?|ppt|txt|json|xml|png|jpe?g|gif|webp|svg|heic|mp3|mp4|wav|mov|webm|opus)(\?|#|$)/i.test(path)) {
    return true;
  }

  if (onChat && pathLower.includes('/backend-api/')) {
    if (pathLower.includes('/estuary/')) return true;
    const idParam = u.searchParams.get('id') || '';
    if (idParam.startsWith('file-')) return true;
  }

  return false;
}

function inferChatGPTAttachmentContext(el) {
  let role = 'unknown';
  let turnNumber = 0;
  const msg = el.closest('[data-message-author-role="user"], [data-message-author-role="assistant"]');
  if (msg) {
    role = msg.getAttribute('data-message-author-role') || 'unknown';
  }
  const turnEl = el.closest('[data-testid^="conversation-turn-"]');
  if (turnEl) {
    const tid = turnEl.getAttribute('data-testid') || '';
    const n = parseInt(tid.replace('conversation-turn-', ''), 10);
    if (n) turnNumber = n;
    const dt = turnEl.getAttribute('data-turn');
    if (dt === 'user' || dt === 'assistant') role = dt;
  }
  return { role, turnNumber };
}

function parseSrcsetFirstUrl(srcset) {
  if (!srcset || typeof srcset !== 'string') return null;
  const part = srcset.split(',')[0]?.trim().split(/\s+/)[0];
  return part || null;
}

/** Depth-first walk including open shadow roots (ChatGPT may hide file UI inside components). */
function walkDeepElementTree(root, callback) {
  if (!root) return;
  function visit(node) {
    if (!node) return;
    if (node.nodeType === 1) {
      callback(node);
      if (node.shadowRoot) visit(node.shadowRoot);
      const kids = node.children;
      if (kids) {
        for (let i = 0; i < kids.length; i++) visit(kids[i]);
      }
    }
  }
  visit(root);
}

/** Pull ChatGPT / OpenAI CDN URLs out of long serialized props (React, etc.). */
function extractHttpsUrlsFromString(str) {
  if (!str || str.length < 28) return [];
  const out = [];
  const re =
    /https:\/\/(?:[\w.-]+\.)?(?:chatgpt\.com|chat\.openai\.com|(?:[\w-]+\.)?oaiusercontent\.com)(?:\/[^\s"'<>\\]*)?/gi;
  let m;
  while ((m = re.exec(str)) !== null) {
    let url = m[0].replace(/\\u0026/g, '&').replace(/&quot;?$/i, '');
    if (url.endsWith('\\')) url = url.slice(0, -1);
    if (url.endsWith(')') || url.endsWith(']') || url.endsWith('"')) url = url.slice(0, -1);
    out.push(url);
  }
  return out;
}

function createChatGPTAttachmentTryPush(files, seen, skippedBlobRef) {
  return function tryPush(absUrl, filename, el, kind) {
    if (!absUrl || absUrl.startsWith('blob:')) {
      if (absUrl && absUrl.startsWith('blob:')) skippedBlobRef.n++;
      return;
    }
    if (typeof isAllowedChatVaultAttachmentDownloadUrl === 'function') {
      if (!isAllowedChatVaultAttachmentDownloadUrl(absUrl)) return;
    }
    const urlOpts =
      kind === 'image' && el ? { allowLooseOaiImage: true, element: el } : {};
    if (!isLikelyChatGPTFileUrl(absUrl, urlOpts)) return;
    if (seen.has(absUrl)) return;
    seen.add(absUrl);
    const ctx = el ? inferChatGPTAttachmentContext(el) : { role: 'unknown', turnNumber: 0 };
    files.push({
      url: absUrl,
      filename: filename || guessChatGPTAttachmentFilename(null, absUrl),
      role: ctx.role,
      turnNumber: ctx.turnNumber,
      kind,
    });
  };
}

/**
 * Collect file URLs: walk entire tree + shadow DOM; parse embedded URLs in attributes.
 * Skips left sidebar (aside) to reduce junk. ChatGPT header attachments often sit
 * outside the scroll region or only appear in serialized data attributes.
 */
function gatherChatGPTAttachmentUrlsDeep(scopeRoot, files, seen, skippedBlobRef) {
  if (!scopeRoot) return;
  const tryPush = createChatGPTAttachmentTryPush(files, seen, skippedBlobRef);

  walkDeepElementTree(scopeRoot, (node) => {
    if (node.tagName === 'SCRIPT' || node.tagName === 'STYLE' || node.tagName === 'NOSCRIPT') return;
    if (node.closest && node.closest('aside')) return;

    if (node.tagName === 'A') {
      const href = (node.getAttribute('href') || '').trim();
      if (href && href !== '#' && !href.startsWith('javascript:')) {
        try {
          const abs = new URL(href, window.location.origin).href;
          tryPush(abs, guessChatGPTAttachmentFilename(node, abs), node, 'link');
        } catch {
          /* ignore */
        }
      }
    }

    if (node.tagName === 'IMG') {
      const src = (node.getAttribute('src') || '').trim();
      if (src && !src.startsWith('data:')) {
        try {
          const abs = new URL(src, window.location.origin).href;
          tryPush(abs, guessFilenameFromImageUrl(abs), node, 'image');
        } catch {
          /* ignore */
        }
      }
      const ss = parseSrcsetFirstUrl(node.getAttribute('srcset'));
      if (ss && !ss.startsWith('data:')) {
        try {
          const abs = new URL(ss, window.location.origin).href;
          tryPush(abs, guessFilenameFromImageUrl(abs), node, 'image');
        } catch {
          /* ignore */
        }
      }
    }

    const attrs = node.attributes;
    if (!attrs || attrs.length === 0) return;
    for (let i = 0; i < attrs.length; i++) {
      const attr = attrs[i];
      const v = (attr.value || '').trim();
      if (v.length < 24) continue;

      if (/^https:\/\//i.test(v) && !/[\s<>"']/.test(v)) {
        try {
          const abs = new URL(v).href;
          if (isLikelyChatGPTFileUrl(abs)) tryPush(abs, guessChatGPTAttachmentFilename(null, abs), node, 'data-attr');
        } catch {
          /* ignore */
        }
      }

      if (v.length > 36 && (v.includes('oaiusercontent') || v.includes('backend-api') || v.includes('estuary'))) {
        extractHttpsUrlsFromString(v).forEach((u) => {
          tryPush(u, guessChatGPTAttachmentFilename(null, u), node, 'embedded');
        });
      }
    }
  });
}

/**
 * No plain URLs in DOM — trigger ChatGPT’s own download behavior (same as clicking the chip).
 */
async function clickChatGPTNativeAttachmentDownloads() {
  const clicked = [];
  const seen = new WeakSet();

  function maybeClick(el) {
    if (!el || seen.has(el)) return;
    seen.add(el);
    clicked.push(el);
  }

  function maybeClickFileChip(el) {
    if (!el || seen.has(el) || el.closest?.('aside')) return;
    const txt = (el.textContent || '').replace(/\s+/g, ' ').trim();
    if (txt.length < 4 || txt.length > 100) return;
    if (!/\.(pdf|docx?|xlsx?|xls|csv|txt|png|jpe?g|gif|webp|svg|zip|json|md|pptx?|rtf|heic)\b/i.test(txt)) return;
    if (/^(send|search|voice|regenerate|copy|good|bad|continue|skip)/i.test(txt)) return;
    if (el.closest('[data-radix-popper-content-wrapper]')) return;
    maybeClick(el);
  }

  const firstUser = document.querySelector('[data-message-author-role="user"]');
  if (firstUser) {
    firstUser.querySelectorAll('[role="button"], button, a').forEach(maybeClickFileChip);
  }

  const mainForSticky = document.querySelector('main');
  if (mainForSticky) {
    mainForSticky.querySelectorAll('[class*="sticky" i]').forEach((root) => {
      root.querySelectorAll('[role="button"], a, button').forEach(maybeClickFileChip);
    });
  }

  walkDeepElementTree(document.body, (node) => {
    if (node.tagName !== 'A' || node.closest?.('aside')) return;
    const href = (node.href || node.getAttribute('href') || '').trim();
    if (!href.startsWith('https://')) return;
    if (!isLikelyChatGPTFileUrl(href)) return;
    maybeClick(node);
  });

  const main = document.querySelector('main');
  if (main) {
    main.querySelectorAll('button[aria-label], [role="button"][aria-label]').forEach((el) => {
      if (el.closest('aside')) return;
      const lab = (el.getAttribute('aria-label') || '').toLowerCase();
      if (
        lab.includes('download') ||
        lab.includes('save file') ||
        (lab.includes('file') && lab.includes('open'))
      ) {
        maybeClick(el);
      }
    });

    main.querySelectorAll('a[download], a[href*="estuary"], a[href*="oaiusercontent"]').forEach((el) => {
      if (!el.closest('aside')) maybeClick(el);
    });

    main.querySelectorAll('[role="button"], button, a').forEach((el) => {
      if (el.closest('aside')) return;
      const txt = (el.textContent || '').replace(/\s+/g, ' ').trim();
      if (txt.length < 4 || txt.length > 100) return;
      if (!/\.(pdf|docx?|xlsx?|xls|csv|txt|png|jpe?g|gif|webp|svg|zip|json|md|pptx?|rtf|heic)\b/i.test(txt)) return;
      if (/^(send|search|voice|regenerate|copy|good|bad|continue)/i.test(txt)) return;
      if (el.closest('textarea') || el.closest('[data-radix-popper-content-wrapper]')) return;
      maybeClick(el);
    });
  }

  let n = 0;
  for (const el of clicked) {
    try {
      el.scrollIntoView({ block: 'center', behavior: 'instant' });
      await wait(80);
      const view = el.ownerDocument?.defaultView;
      if (view && typeof view.MouseEvent === 'function') {
        const opts = { bubbles: true, cancelable: true, view };
        el.dispatchEvent(new view.MouseEvent('pointerdown', opts));
        el.dispatchEvent(new view.MouseEvent('pointerup', opts));
        el.dispatchEvent(new view.MouseEvent('click', opts));
      }
      if (typeof el.click === 'function') el.click();
      n++;
    } catch (err) {
      console.warn('[ChatVault] attachment click failed:', err);
    }
    await wait(500);
  }
  return n;
}

function mimeStringToFileExtension(mimeRaw) {
  if (!mimeRaw || typeof mimeRaw !== 'string') return '';
  const m = decodeURIComponent(mimeRaw).split(';')[0].trim().toLowerCase();
  const map = {
    'application/pdf': '.pdf',
    'image/png': '.png',
    'image/jpeg': '.jpg',
    'image/jpg': '.jpg',
    'image/webp': '.webp',
    'image/gif': '.gif',
    'image/svg+xml': '.svg',
    'text/plain': '.txt',
    'text/csv': '.csv',
    'text/markdown': '.md',
    'application/json': '.json',
    'application/zip': '.zip',
    'application/vnd.openxmlformats-officedocument.wordprocessingml.document': '.docx',
    'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet': '.xlsx',
    'application/vnd.openxmlformats-officedocument.presentationml.presentation': '.pptx',
  };
  return map[m] || '';
}

function parseFilenameFromRscdParam(rscd) {
  if (!rscd || typeof rscd !== 'string') return null;
  const decoded = (() => {
    try {
      return decodeURIComponent(rscd.replace(/\+/g, ' '));
    } catch {
      return rscd;
    }
  })();
  let m = decoded.match(/filename\*\s*=\s*UTF-8''([^;\n]+)/i);
  if (m) {
    try {
      return decodeURIComponent(m[1].trim().replace(/^["']|["']$/g, ''));
    } catch {
      return m[1].trim();
    }
  }
  m = decoded.match(/filename\s*=\s*"([^"]+)"/i) || decoded.match(/filename\s*=\s*([^;\n]+)/i);
  if (m) return m[1].trim().replace(/^["']|["']$/g, '');
  return null;
}

function guessChatGPTAttachmentFilename(anchor, absUrl) {
  const dl = anchor && anchor.getAttribute('download');
  if (dl && dl.trim()) return dl.trim().split('/').pop();

  const label = anchor && (anchor.getAttribute('aria-label') || anchor.getAttribute('title'));
  if (label && /\.[a-z0-9]{2,5}$/i.test(label.trim())) return label.trim().split(/\s+/)[0];

  const text = anchor && anchor.textContent ? anchor.textContent.trim() : '';
  if (text && text.length < 200 && /\.[a-z0-9]{2,5}$/i.test(text)) return text.split(/\s+/)[0];

  try {
    const u = new URL(absUrl);
    const fp = u.searchParams.get('filename') || u.searchParams.get('name');
    if (fp) return fp.split('/').pop();

    const rscd = u.searchParams.get('rscd');
    if (rscd) {
      const fromRscd = parseFilenameFromRscdParam(rscd);
      if (fromRscd) return fromRscd.split('/').pop();
    }

    const last = decodeURIComponent(u.pathname.split('/').pop() || '');
    if (last && last !== 'download' && last.includes('.')) return last;

    const fid = u.searchParams.get('id');
    const rsct = u.searchParams.get('rsct');
    if (fid && fid.startsWith('file-') && rsct) {
      const ext = mimeStringToFileExtension(rsct);
      if (ext) return `${fid}${ext}`;
    }
    if (fid && fid.startsWith('file-')) return fid;

    const rsp = u.searchParams.get('response-content-disposition');
    if (rsp) {
      const fromRsp = parseFilenameFromRscdParam(rsp);
      if (fromRsp) return fromRsp.split('/').pop();
    }
  } catch {
    /* ignore */
  }
  return 'download';
}

function guessFilenameFromImageUrl(absUrl) {
  const g = guessChatGPTAttachmentFilename(null, absUrl);
  if (g && g !== 'download' && g !== 'attachment') return g;
  try {
    const u = new URL(absUrl);
    const last = decodeURIComponent(u.pathname.split('/').pop() || '');
    if (last && /\.[a-z0-9]{2,8}$/i.test(last)) return last;
  } catch {
    /* ignore */
  }
  return 'download';
}

async function collectChatGPTAttachments() {
  const startTime = Date.now();
  const scrollContainer = findChatGPTScrollContainer();
  if (!scrollContainer) {
    return { success: false, error: 'Could not find chat scroll area', files: [] };
  }

  await scrollToLoadAll(
    scrollContainer,
    () => getChatGPTTurnContainerNodes().length,
    startTime
  );

  const seen = new Set();
  const files = [];
  const skippedBlobRef = { n: 0 };

  gatherChatGPTAttachmentUrlsDeep(document.body, files, seen, skippedBlobRef);

  let mainWorldRawCount = 0;
  let mainWorldError = null;
  if (files.length === 0) {
    try {
      const mw = await new Promise((resolve) => {
        chrome.runtime.sendMessage({ action: 'chatgptMainWorldHarvest' }, (r) => {
          if (chrome.runtime.lastError) {
            resolve({ success: false, urls: [], error: chrome.runtime.lastError.message });
          } else {
            resolve(r || {});
          }
        });
      });
      mainWorldError = mw.error || null;
      if (mw.success && Array.isArray(mw.urls) && mw.urls.length > 0) {
        mainWorldRawCount = mw.urls.length;
        const tryPush = createChatGPTAttachmentTryPush(files, seen, skippedBlobRef);
        for (const u of mw.urls) {
          if (typeof u === 'string') {
            tryPush(u, guessChatGPTAttachmentFilename(null, u), null, 'react-props');
          }
        }
      }
    } catch (err) {
      mainWorldError = err.message;
      console.warn('[ChatVault] MAIN-world harvest error:', err);
    }
  }

  let usedUiClickFallback = false;
  let uiClickCount = 0;
  if (files.length === 0) {
    usedUiClickFallback = true;
    uiClickCount = await clickChatGPTNativeAttachmentDownloads();
  }

  let skippedBlob = skippedBlobRef.n;

  let chatTitle = '';
  let chatId = '';
  const currentChatId = window.location.pathname.match(/\/c\/([^/?]+)/)?.[1];
  if (currentChatId) chatId = currentChatId;
  const fromTitle = document.title?.replace(/\s*[-|]\s*ChatGPT.*$/i, '').trim();
  if (fromTitle) chatTitle = fromTitle;

  let outFiles = files;
  if (typeof isAllowedChatVaultAttachmentDownloadUrl === 'function') {
    outFiles = files.filter((f) => f && f.url && isAllowedChatVaultAttachmentDownloadUrl(f.url));
  }

  const warnings = [];
  if (files.length > outFiles.length) {
    warnings.push(
      `${files.length - outFiles.length} file URL(s) skipped (host not allowlisted for download).`
    );
  }
  if (skippedBlob > 0) {
    warnings.push(
      `${skippedBlob} blob: link(s) skipped; use ChatGPT’s UI to save those files if needed.`
    );
  }
  if (outFiles.some((f) => f.kind === 'react-props')) {
    warnings.push('Some file URLs were read from ChatGPT’s in-page React state (not visible as normal HTML links).');
  }
  if (usedUiClickFallback && uiClickCount > 0) {
    warnings.push(
      `Used ChatGPT’s on-page controls for ${uiClickCount} item(s) (no direct file URLs were found in the DOM).`
    );
  }

  return {
    success: true,
    files: outFiles,
    usedUiClickFallback,
    uiClickCount,
    mainWorldRawCount,
    mainWorldError,
    chatTitle,
    chatId,
    skippedBlob,
    warnings,
  };
}


// --- src/extractors/gemini.js ---
// =============================================================================
// Chat Archive — Gemini Extractor (Pass 0 + Direct Text Fallback)
// =============================================================================
// Architecture: Appendix D
// Turn container: div.conversation-container[id] wraps <user-query> + <model-response>
// Copy buttons: aria-label="Copy prompt" (user), data-test-id="copy-button" (assistant)
// Role signals: <user-query> (0.99), <model-response> (0.99)

async function extractGeminiConversation() {
  const startTime = Date.now();
  const turns = [];
  const errors = [];

  // 1. Find scroll container
  const scrollContainer = findGeminiScrollContainer();
  if (!scrollContainer) {
    return { turns: [], errors: ['Scroll container not found'], partial: true };
  }

  // 2. Load all turns
  await scrollToLoadAll(
    scrollContainer,
    'div.conversation-container[id]',
    startTime
  );

  // 3. Get turn containers
  const turnContainers = document.querySelectorAll('div.conversation-container[id]');
  console.log(`[Chat Archive] Gemini: Found ${turnContainers.length} turn containers`);

  if (turnContainers.length === 0) {
    // Fallback: try older selectors
    const oldContainers = document.querySelectorAll('ms-chat-turn');
    if (oldContainers.length > 0) {
      console.log(`[Chat Archive] Gemini: Found ${oldContainers.length} legacy ms-chat-turn elements`);
      return extractGeminiLegacy(oldContainers, startTime);
    }
    return { turns: [], errors: ['No turn containers found'], partial: true };
  }

  // 4. Clipboard test
  const hasClipboard = await testClipboardAccess();
  console.log(`[Chat Archive] Gemini: Clipboard access: ${hasClipboard}`);

  // 5. Extract each turn pair
  for (let i = 0; i < turnContainers.length; i++) {
    if (Date.now() - startTime > SAFETY_LIMITS.MAX_EXTRACTION_TIME_MS) {
      errors.push(`Extraction timed out after ${SAFETY_LIMITS.MAX_EXTRACTION_TIME_MS}ms`);
      break;
    }
    if (turns.length >= SAFETY_LIMITS.MAX_TURNS) {
      errors.push(`Hit maximum turn limit (${SAFETY_LIMITS.MAX_TURNS})`);
      break;
    }

    const container = turnContainers[i];
    const turnId = container.id;

    try {
      container.scrollIntoView({ behavior: 'instant', block: 'center' });
      await wait(200);

      // --- User turn ---
      const userQuery = container.querySelector('user-query');
      if (userQuery) {
        const userTurn = await extractGeminiUserTurn(userQuery, turnId, hasClipboard);
        if (userTurn) turns.push(flagIfOversized(userTurn));
      }

      // --- Assistant turn ---
      const modelResponse = container.querySelector('model-response');
      if (modelResponse) {
        const assistantTurn = await extractGeminiAssistantTurn(modelResponse, turnId, hasClipboard);
        if (assistantTurn) turns.push(flagIfOversized(assistantTurn));
      }
    } catch (err) {
      errors.push(`Error extracting container ${i} (${turnId}): ${err.message}`);
      console.warn(`[Chat Archive] Gemini: Error on container ${i}:`, err);
    }
  }

  console.log(`[Chat Archive] Gemini: Extracted ${turns.length} turns, ${errors.length} errors`);
  return { turns, errors, partial: errors.length > 0 };
}

async function extractGeminiUserTurn(userQuery, turnId, hasClipboard) {
  let content = null;
  let extractionMethod = 'direct';

  // Pass 0: Copy button
  if (hasClipboard) {
    try {
      const copyBtn = userQuery.querySelector('button[aria-label="Copy prompt"]')
        || findActionButton(userQuery, ['Copy prompt', 'Copy']);
      if (copyBtn) {
        const clipContent = await clickCopyAndRead(copyBtn);
        if (clipContent && clipContent.trim().length > 0) {
          content = clipContent;
          extractionMethod = 'clipboard';
        }
      }
    } catch (err) {
      console.warn(`[Chat Archive] Gemini: User clipboard failed:`, err);
    }
  }

  // Fallback: direct text
  if (!content) {
    const textEl = userQuery.querySelector('.query-text-line');
    content = textEl?.textContent?.trim() || '';

    // Broader fallback
    if (!content) {
      const queryText = userQuery.querySelector('.query-text');
      content = queryText?.textContent?.trim() || '';
    }
    if (!content) {
      content = userQuery.textContent?.trim() || '';
    }
    extractionMethod = 'direct';
  }

  if (!content || content.trim().length === 0) return null;

  let timestamp;
  const timeEl = userQuery.querySelector('time[datetime]');
  if (timeEl) {
    const dt = timeEl.getAttribute('datetime');
    if (dt && dt.trim()) timestamp = dt.trim();
  }

  return {
    role: 'user',
    content: content.trim(),
    turnId,
    extractionMethod,
    confidence: 0.99,
    classificationSource: 'structural',
    timestamp,
  };
}

async function extractGeminiAssistantTurn(modelResponse, turnId, hasClipboard) {
  let content = null;
  let extractionMethod = 'direct';

  // Pass 0: Copy button
  if (hasClipboard) {
    try {
      const copyBtn = modelResponse.querySelector('button[data-test-id="copy-button"]')
        || modelResponse.querySelector('button[aria-label="Copy"]')
        || findActionButton(modelResponse, ['Copy']);
      if (copyBtn) {
        const clipContent = await clickCopyAndRead(copyBtn);
        if (clipContent && clipContent.trim().length > 0) {
          content = clipContent;
          extractionMethod = 'clipboard';
        }
      }
    } catch (err) {
      console.warn(`[Chat Archive] Gemini: Assistant clipboard failed:`, err);
    }
  }

  // Fallback: direct text (with citation stripping)
  if (!content) {
    content = extractGeminiAssistantDirectText(modelResponse);
    extractionMethod = 'direct';
  }

  if (!content || content.trim().length === 0) return null;

  return {
    role: 'assistant',
    content: content.trim(),
    turnId,
    extractionMethod,
    confidence: 0.99,
    classificationSource: 'structural',
  };
}

/**
 * Direct text extraction for Gemini assistant messages.
 * Clones the element and strips citations, avatars, processing states.
 */
function extractGeminiAssistantDirectText(modelResponse) {
  const markdown = modelResponse.querySelector('.markdown.markdown-main-panel');
  if (!markdown) {
    // Broader fallback
    const messageContent = modelResponse.querySelector('message-content');
    if (messageContent) {
      const clone = messageContent.cloneNode(true);
      stripGeminiDecorations(clone);
      return clone.textContent?.trim() || '';
    }
    return modelResponse.textContent?.trim() || '';
  }

  const clone = markdown.cloneNode(true);
  stripGeminiDecorations(clone);
  return clone.textContent?.trim() || '';
}

/**
 * Remove decorative/non-content elements from a Gemini DOM clone.
 */
function stripGeminiDecorations(element) {
  const selectorsToRemove = [
    'source-footnote',
    'source-inline-chip',
    'sources-carousel-inline',
    'bard-avatar',
    'processing-state',
    'tts-control',
    'thumb-up-button',
    'thumb-down-button',
    'copy-button',
    '.code-block-decoration',
    'freemium-rag-disclaimer',
    'sensitive-memories-banner',
  ];

  for (const selector of selectorsToRemove) {
    try {
      element.querySelectorAll(selector).forEach((el) => el.remove());
    } catch {
      // Invalid selector — skip
    }
  }
}

/**
 * Legacy Gemini extraction for older DOM structure (ms-chat-turn).
 */
async function extractGeminiLegacy(turnElements, startTime) {
  const turns = [];
  const errors = [];

  for (let i = 0; i < turnElements.length; i++) {
    if (Date.now() - startTime > SAFETY_LIMITS.MAX_EXTRACTION_TIME_MS) break;
    if (turns.length >= SAFETY_LIMITS.MAX_TURNS) break;

    try {
      const el = turnElements[i];
      const content = el.textContent?.trim() || '';
      if (!content) continue;

      // Legacy role detection: alternating pattern
      turns.push({
        role: i % 2 === 0 ? 'user' : 'assistant',
        content,
        extractionMethod: 'direct',
        confidence: 0.60,
        classificationSource: 'heuristic-alternation',
      });
    } catch (err) {
      errors.push(`Legacy turn ${i}: ${err.message}`);
    }
  }

  return { turns, errors, partial: true };
}

function findGeminiScrollContainer() {
  const strategies = [
    () => document.querySelector('infinite-scroller[data-test-id="chat-history-container"]'),
    () => document.querySelector('#chat-history'),
    () => document.querySelector('.chat-history-scroll-container'),
    () => {
      const firstTurn = document.querySelector('div.conversation-container[id]');
      return firstTurn ? findScrollableAncestor(firstTurn) : null;
    },
  ];

  for (const strategy of strategies) {
    const result = strategy();
    if (result) return result;
  }
  return null;
}


// --- src/extractors/grok.js ---
// =============================================================================
// Chat Archive — Grok.com Extractor (Pass 0 + Direct Text Fallback)
// =============================================================================
// Architecture: Appendix A
// Turn container: div[id^="response-"] with scroll-margin-top
// Copy buttons: aria-label="Copy" on both roles (opacity-0 but clickable)
// Role signals: items-end (user) vs items-start (assistant) — 0.95
//               Button count: 2 (user) vs 8+ (assistant) — 0.95
//               Bubble styling: bg-surface-l1 (user) vs w-full (assistant) — 0.90

async function extractGrokConversation() {
  const startTime = Date.now();
  const turns = [];
  const errors = [];

  // 1. Find scroll container
  const scrollContainer = findGrokScrollContainer();
  if (!scrollContainer) {
    return { turns: [], errors: ['Scroll container not found'], partial: true };
  }

  // 2. Load all turns
  await scrollToLoadAll(scrollContainer, 'div[id^="response-"]', startTime);

  // 3. Get turn containers
  const turnContainers = document.querySelectorAll('div[id^="response-"]');
  console.log(`[Chat Archive] Grok: Found ${turnContainers.length} turn containers`);

  if (turnContainers.length === 0) {
    return { turns: [], errors: ['No turn containers found'], partial: true };
  }

  // 4. Clipboard test
  const hasClipboard = await testClipboardAccess();
  console.log(`[Chat Archive] Grok: Clipboard access: ${hasClipboard}`);

  // 5. Extract each turn
  for (let i = 0; i < turnContainers.length; i++) {
    if (Date.now() - startTime > SAFETY_LIMITS.MAX_EXTRACTION_TIME_MS) {
      errors.push(`Extraction timed out after ${SAFETY_LIMITS.MAX_EXTRACTION_TIME_MS}ms`);
      break;
    }
    if (turns.length >= SAFETY_LIMITS.MAX_TURNS) {
      errors.push(`Hit maximum turn limit (${SAFETY_LIMITS.MAX_TURNS})`);
      break;
    }

    const container = turnContainers[i];

    try {
      container.scrollIntoView({ behavior: 'instant', block: 'center' });
      await wait(150);

      const turn = await extractGrokTurn(container, hasClipboard);
      if (turn) turns.push(flagIfOversized(turn));
    } catch (err) {
      errors.push(`Error extracting turn ${i}: ${err.message}`);
      console.warn(`[Chat Archive] Grok: Error on turn ${i}:`, err);
    }
  }

  console.log(`[Chat Archive] Grok: Extracted ${turns.length} turns, ${errors.length} errors`);
  return { turns, errors, partial: errors.length > 0 };
}

async function extractGrokTurn(container, hasClipboard) {
  const turnId = container.id; // "response-{uuid}"

  // --- Role detection (3 independent signals) ---
  const role = detectGrokRole(container);
  if (!role) return null;

  // --- Pass 0: Clipboard ---
  let content = null;
  let extractionMethod = 'direct';

  if (hasClipboard) {
    try {
      const copyBtn = container.querySelector('button[aria-label="Copy"]')
        || findActionButton(container, ['Copy']);
      if (copyBtn) {
        const clipContent = await clickCopyAndRead(copyBtn);
        if (clipContent && clipContent.trim().length > 0) {
          content = clipContent;
          extractionMethod = 'clipboard';
        }
      }
    } catch (err) {
      console.warn(`[Chat Archive] Grok: Clipboard failed for ${turnId}:`, err);
    }
  }

  // --- Fallback: Direct text ---
  if (!content) {
    content = extractGrokDirectText(container, role);
    extractionMethod = 'direct';
  }

  if (!content || content.trim().length === 0) return null;

  let timestamp;
  const timeEl = container.querySelector('time[datetime]');
  if (timeEl) {
    const dt = timeEl.getAttribute('datetime');
    if (dt && dt.trim()) timestamp = dt.trim();
  }

  return {
    role,
    content: content.trim(),
    turnId,
    extractionMethod,
    confidence: 0.95,
    classificationSource: 'structural',
    timestamp,
  };
}

/**
 * Detect role using three independent signals.
 * Signal 1: Container alignment (items-end = user, items-start = assistant)
 * Signal 2: Button count (2 = user, 8+ = assistant)
 * Signal 3: Message bubble styling (bg-surface-l1 = user)
 */
function detectGrokRole(container) {
  const signals = { user: 0, assistant: 0 };

  // Signal 1: Alignment classes
  const classes = container.className || '';
  if (classes.includes('items-end')) signals.user += 2;
  else if (classes.includes('items-start')) signals.assistant += 2;

  // Also check child flex containers for alignment
  const flexChild = container.querySelector('[class*="items-end"]');
  const flexChildStart = container.querySelector('[class*="items-start"]');
  if (flexChild && !flexChildStart) signals.user += 1;
  if (flexChildStart && !flexChild) signals.assistant += 1;

  // Signal 2: Button count
  const buttons = container.querySelectorAll('button');
  if (buttons.length <= 3) signals.user += 2;
  else if (buttons.length >= 5) signals.assistant += 2;

  // Signal 3: Bubble styling
  const hasBubble = container.querySelector('[class*="bg-surface-l1"]');
  const hasFullWidth = container.querySelector('[class*="max-w-none"]');
  if (hasBubble) signals.user += 1;
  if (hasFullWidth) signals.assistant += 1;

  // Signal 4: Edit button (user only)
  const editBtn = container.querySelector('button[aria-label="Edit"]');
  if (editBtn) signals.user += 2;

  // Signal 5: Regenerate button (assistant only)
  const regenBtn = container.querySelector('button[aria-label="Regenerate"]');
  if (regenBtn) signals.assistant += 2;

  // Signal 6: Response time indicator (assistant only)
  const responseTime = container.querySelector('[class*="text-xs"]');
  if (responseTime && /\d+ms/.test(responseTime.textContent || '')) {
    signals.assistant += 1;
  }

  if (signals.user > signals.assistant) return 'user';
  if (signals.assistant > signals.user) return 'assistant';

  // Tie-breaker: default to alternation pattern (handled by heuristics pass)
  return null;
}

function extractGrokDirectText(container, role) {
  // Look for the message content area
  const markdown = container.querySelector('.message-bubble .response-content-markdown');
  if (markdown) return markdown.textContent?.trim() || '';

  // Broader: any .markdown inside the container
  const markdownAlt = container.querySelector('.markdown');
  if (markdownAlt) return markdownAlt.textContent?.trim() || '';

  // Broadest: main text content, excluding buttons
  const clone = container.cloneNode(true);
  // Remove action bars, follow-up suggestions
  clone.querySelectorAll('button, [class*="follow-up"], #last-reply-container').forEach(
    (el) => el.remove()
  );
  return clone.textContent?.trim() || '';
}

function findGrokScrollContainer() {
  const strategies = [
    () => document.querySelector('.w-full.h-full.overflow-y-auto.overflow-x-hidden'),
    () => document.querySelector('[class*="overflow-y-auto"][class*="scrollbar-gutter"]'),
    () => {
      const firstTurn = document.querySelector('div[id^="response-"]');
      return firstTurn ? findScrollableAncestor(firstTurn) : null;
    },
  ];

  for (const strategy of strategies) {
    const result = strategy();
    if (result) return result;
  }
  return null;
}


// --- src/extractors/grok-x.js ---
// =============================================================================
// Chat Archive — Grok x.com Extractor (Pass 0 + Direct Text Fallback)
// =============================================================================
// Architecture: Appendix B
// CRITICAL: x.com/i/grok has ZERO common selectors with grok.com
// Framework: React Native Web (hashed classes: css-175oi2r, r-*)
// Copy button: aria-label="Copy text" on ASSISTANT only
// User turns: NO copy button — must use direct text extraction
// Role signals: follow_ups_list presence (assistant), button presence

async function extractGrokXConversation() {
  const startTime = Date.now();
  const turns = [];
  const errors = [];

  // 1. Find scroll container — no reliable selector, walk up from content
  const scrollContainer = findGrokXScrollContainer();
  if (!scrollContainer) {
    return { turns: [], errors: ['Scroll container not found'], partial: true };
  }

  // 2. Scroll to load all content
  // x.com Grok doesn't have clean turn containers — we need to identify turn boundaries
  await scrollToLoadAllGrokX(scrollContainer, startTime);

  // 3. Identify turn blocks
  // x.com Grok uses flat sibling divs without per-turn IDs.
  // Strategy: find all "Copy text" buttons (assistant markers) and work outward
  const turnBlocks = identifyGrokXTurnBlocks();
  console.log(`[Chat Archive] Grok-X: Identified ${turnBlocks.length} turn blocks`);

  if (turnBlocks.length === 0) {
    return { turns: [], errors: ['No turn blocks identified'], partial: true };
  }

  // 4. Clipboard test
  const hasClipboard = await testClipboardAccess();
  console.log(`[Chat Archive] Grok-X: Clipboard access: ${hasClipboard}`);

  // 5. Extract each turn
  for (let i = 0; i < turnBlocks.length; i++) {
    if (Date.now() - startTime > SAFETY_LIMITS.MAX_EXTRACTION_TIME_MS) {
      errors.push(`Extraction timed out`);
      break;
    }
    if (turns.length >= SAFETY_LIMITS.MAX_TURNS) {
      errors.push(`Hit maximum turn limit`);
      break;
    }

    const block = turnBlocks[i];

    try {
      block.element.scrollIntoView({ behavior: 'instant', block: 'center' });
      await wait(150);

      const turn = await extractGrokXTurn(block, hasClipboard);
      if (turn) turns.push(flagIfOversized(turn));
    } catch (err) {
      errors.push(`Error on block ${i}: ${err.message}`);
      console.warn(`[Chat Archive] Grok-X: Error on block ${i}:`, err);
    }
  }

  console.log(`[Chat Archive] Grok-X: Extracted ${turns.length} turns, ${errors.length} errors`);
  return { turns, errors, partial: errors.length > 0 };
}

/**
 * Identify turn blocks in x.com/i/grok's flat DOM structure.
 * Strategy: 
 *   - Assistant turns have "Copy text" buttons and/or follow_ups_list
 *   - User turns are the blocks between assistant turns that have no action buttons
 */
function identifyGrokXTurnBlocks() {
  const blocks = [];

  // Find all major content containers in the chat area
  // x.com uses deeply nested divs with hashed classes
  // Best approach: find all "Copy text" buttons and their ancestor containers
  const copyButtons = document.querySelectorAll('button[aria-label="Copy text"]');
  const followUps = document.querySelectorAll('[data-testid="follow_ups_list"]');

  // Build a set of assistant container elements
  const assistantContainers = new Set();
  const assistantElements = [];

  for (const btn of copyButtons) {
    // Walk up to find the turn-level container
    // Typically: button → action bar → content block → turn container
    let container = btn.parentElement;
    for (let depth = 0; depth < 8 && container; depth++) {
      // Heuristic: turn containers tend to be direct children of the main scroll area
      if (container.parentElement &&
          container.parentElement.children.length > 2 &&
          container.previousElementSibling) {
        break;
      }
      container = container.parentElement;
    }
    if (container && !assistantContainers.has(container)) {
      assistantContainers.add(container);
      assistantElements.push({ element: container, role: 'assistant', copyButton: btn });
    }
  }

  // If we found assistant containers, their siblings before each are likely user turns
  if (assistantElements.length > 0) {
    // Get the parent that holds all turn siblings
    const parent = assistantElements[0].element.parentElement;
    if (!parent) return assistantElements;

    const children = Array.from(parent.children);
    let lastAssistantIdx = -1;

    for (let i = 0; i < children.length; i++) {
      const child = children[i];

      if (assistantContainers.has(child)) {
        // Everything between lastAssistantIdx and this is user content
        // But often there's just one user block before each assistant
        if (i > 0 && i - 1 > lastAssistantIdx) {
          // Check each block between last assistant and this assistant
          for (let j = lastAssistantIdx + 1; j < i; j++) {
            const candidate = children[j];
            const text = candidate.textContent?.trim() || '';
            // Filter out empty blocks, navigation, follow-ups
            if (text.length > 0 &&
                !candidate.querySelector('[data-testid="follow_ups_list"]') &&
                !candidate.querySelector('button[aria-label="Copy text"]') &&
                !candidate.querySelector('textarea')) {
              blocks.push({ element: candidate, role: 'user', copyButton: null });
            }
          }
        }
        blocks.push(assistantContainers.has(child)
          ? assistantElements.find((a) => a.element === child) || { element: child, role: 'assistant', copyButton: null }
          : { element: child, role: 'assistant', copyButton: null });
        lastAssistantIdx = i;
      }
    }

    return blocks;
  }

  // Fallback: no assistant markers found — try raw text extraction with heuristics
  return [];
}

async function extractGrokXTurn(block, hasClipboard) {
  const { element, role, copyButton } = block;

  let content = null;
  let extractionMethod = 'direct';

  // --- Pass 0: Clipboard (assistant only on x.com) ---
  if (role === 'assistant' && hasClipboard && copyButton) {
    try {
      const clipContent = await clickCopyAndRead(copyButton);
      if (clipContent && clipContent.trim().length > 0) {
        content = clipContent;
        extractionMethod = 'clipboard';
      }
    } catch (err) {
      console.warn(`[Chat Archive] Grok-X: Assistant clipboard failed:`, err);
    }
  }

  // --- Direct text extraction ---
  if (!content) {
    content = extractGrokXDirectText(element, role);
    extractionMethod = 'direct';
  }

  if (!content || content.trim().length === 0) return null;

  return {
    role,
    content: content.trim(),
    extractionMethod,
    confidence: role === 'assistant' ? 0.95 : 0.80,
    classificationSource: 'structural',
  };
}

function extractGrokXDirectText(element, role) {
  // Clone and strip non-content elements
  const clone = element.cloneNode(true);

  // Remove follow-up suggestions, buttons, textareas
  clone.querySelectorAll(
    '[data-testid="follow_ups_list"], button, textarea, svg, [role="img"]'
  ).forEach((el) => el.remove());

  // For user turns, look for the specific text container class
  if (role === 'user') {
    // x.com Grok user text containers have class r-1kt6imw
    const userText = element.querySelector('[class*="r-1kt6imw"]');
    if (userText) return userText.textContent?.trim() || '';
  }

  // For assistant turns, look for formatted content
  if (role === 'assistant') {
    const assistantText = element.querySelector('[class*="r-rjixqe"]');
    if (assistantText) return assistantText.textContent?.trim() || '';
  }

  return clone.textContent?.trim() || '';
}

async function scrollToLoadAllGrokX(scrollContainer, startTime) {
  let previousHeight = 0;
  let stableIterations = 0;
  let scrollIterations = 0;

  scrollContainer.scrollTop = 0;
  await wait(500);

  while (
    stableIterations < SAFETY_LIMITS.SCROLL_STABILITY_THRESHOLD &&
    scrollIterations < SAFETY_LIMITS.MAX_SCROLL_ITERATIONS
  ) {
    if (startTime && Date.now() - startTime > SAFETY_LIMITS.MAX_EXTRACTION_TIME_MS) break;

    const currentHeight = scrollContainer.scrollHeight;
    if (currentHeight === previousHeight) {
      stableIterations++;
    } else {
      stableIterations = 0;
      previousHeight = currentHeight;
    }

    scrollContainer.scrollBy(0, scrollContainer.clientHeight * 0.8);
    await wait(SAFETY_LIMITS.SCROLL_STEP_DELAY_MS);
    scrollIterations++;
  }

  scrollContainer.scrollTop = 0;
  await wait(200);
}

function findGrokXScrollContainer() {
  const strategies = [
    // x.com's Grok chat area
    () => {
      const grokSection = document.querySelector('[data-testid="GrokChat"]');
      if (grokSection) {
        const scrollable = grokSection.querySelector('[class*="overflow-y-auto"]')
          || grokSection.querySelector('[style*="overflow"]');
        if (scrollable) return scrollable;
        return findScrollableAncestor(grokSection);
      }
      return null;
    },
    // Generic: find scrollable ancestor of first copy button
    () => {
      const firstBtn = document.querySelector('button[aria-label="Copy text"]');
      return firstBtn ? findScrollableAncestor(firstBtn) : null;
    },
    // Broadest: main scrollable area on x.com
    () => document.querySelector('main [class*="overflow"][class*="auto"]'),
  ];

  for (const strategy of strategies) {
    const result = strategy();
    if (result) return result;
  }
  return null;
}


// --- src/extractors/perplexity.js ---
// =============================================================================
// Chat Archive — Perplexity.ai Extractor (Pass 0 + Direct Text Fallback)
// =============================================================================
// Architecture: Similar to Greasy Fork Perplexity Chat Exporter
// User query: button[data-testid="copy-query-button"] or button[aria-label="Copy Query"]
// Assistant: button[aria-label="Copy"] (with SVG, excludes pre/code blocks)
// Content: .whitespace-pre-line.text-pretty.break-words (user), .prose (assistant)
// Thread container: .max-w-threadContentWidth, [class*="threadContentWidth"], or main

async function extractPerplexityConversation(options = {}) {
  const startTime = Date.now();
  const turns = [];
  const errors = [];

  const scrollContainer = findPerplexityScrollContainer();
  console.log('[Chat Archive] Perplexity: Scroll container found:', scrollContainer?.tagName, scrollContainer?.className);
  if (!scrollContainer) {
    return { turns: [], errors: ['Scroll container not found'], partial: true };
  }

  // Visual indicator: flash the scroll container border
  const originalBorder = scrollContainer.style.border;
  scrollContainer.style.border = '3px solid red';
  await wait(500);
  scrollContainer.style.border = originalBorder;

  // Always scroll to load all content (Perplexity lazy-loads)
  console.log('[Chat Archive] Perplexity: Starting scroll-to-load...');
  const scrollCount = await scrollToLoadAll(
    scrollContainer,
    'button[aria-label="Copy query"], button[data-testid="copy-query-button"], button[aria-label="Copy Query"], .prose.text-pretty',
    startTime
  );
  console.log('[Chat Archive] Perplexity: Scroll complete, performed', scrollCount, 'scrolls');

  // Skip clipboard for Perplexity - it's too slow for project exports (can exceed 30s message timeout)
  // Use direct text extraction only for speed
  console.log(`[Chat Archive] Perplexity: Using direct text extraction (skipping clipboard for speed)`);

  const queryButtons = Array.from(document.querySelectorAll('button[aria-label="Copy query"], button[data-testid="copy-query-button"], button[aria-label="Copy Query"]'))
    .filter((btn) => !btn.closest('pre, code'));
  const responseButtons = Array.from(document.querySelectorAll('button[aria-label="Copy"]'))
    .filter((btn) => {
      if (btn.closest('pre, code')) return false;
      if (btn.querySelector('svg')) return true;
      return false;
    });

  const allItems = [
    ...queryButtons.map((btn) => ({ btn, role: 'user' })),
    ...responseButtons.map((btn) => ({ btn, role: 'assistant' })),
  ].sort((a, b) => a.btn.getBoundingClientRect().top - b.btn.getBoundingClientRect().top);

  const processedHashes = new Set();

  for (const { btn, role } of allItems) {
    if (Date.now() - startTime > SAFETY_LIMITS.MAX_EXTRACTION_TIME_MS) {
      errors.push(`Extraction timed out after ${SAFETY_LIMITS.MAX_EXTRACTION_TIME_MS}ms`);
      break;
    }
    if (turns.length >= SAFETY_LIMITS.MAX_TURNS) {
      errors.push(`Hit maximum turn limit (${SAFETY_LIMITS.MAX_TURNS})`);
      break;
    }

    try {
      // Direct text extraction only (no clipboard, no scrollIntoView, no waits)
      const content = role === 'user'
        ? extractPerplexityUserDirectText(btn)
        : extractPerplexityAssistantDirectText(btn);

      if (!content || content.trim().length === 0) continue;

      const hash = content.substring(0, 150) + content.length + '|' + role;
      if (processedHashes.has(hash)) continue;
      processedHashes.add(hash);

      turns.push(flagIfOversized({
        role,
        content: content.trim(),
        extractionMethod: 'direct',
        confidence: 0.95,
        classificationSource: 'structural',
      }));
    } catch (err) {
      errors.push(`Error extracting ${role} turn: ${err.message}`);
      console.warn(`[Chat Archive] Perplexity: Error:`, err);
    }
  }

  console.log(`[Chat Archive] Perplexity: Extracted ${turns.length} turns, ${errors.length} errors`);
  return { turns, errors, partial: errors.length > 0 };
}

function findPerplexityUserRoot(btn) {
  let node = btn;
  for (let d = 0; d < 12 && node && node !== document.body; d++) {
    if (node.querySelector?.('.whitespace-pre-line.text-pretty.break-words, span[data-lexical-text="true"], span.select-text')) {
      return node;
    }
    node = node.parentElement;
  }
  return btn.parentElement;
}

function findPerplexityAssistantRoot(btn) {
  let node = btn;
  for (let d = 0; d < 12 && node && node !== document.body; d++) {
    if (node.querySelector?.('.prose.text-pretty, [data-testid="answer"], [data-testid="assistant"]')) {
      return node;
    }
    node = node.parentElement;
  }
  return btn.parentElement;
}

function extractPerplexityUserDirectText(btn) {
  const root = findPerplexityUserRoot(btn);
  const textEl = root?.querySelector('.whitespace-pre-line.text-pretty.break-words, span[data-lexical-text="true"], span.select-text');
  if (textEl) return textEl.textContent?.trim() || '';
  return root?.textContent?.trim() || '';
}

function extractPerplexityAssistantDirectText(btn) {
  const root = findPerplexityAssistantRoot(btn);
  const prose = root?.querySelector('.prose.text-pretty.dark\\:prose-invert, .prose, [data-testid="answer"], [data-testid="assistant"]');
  if (prose) return prose.textContent?.trim() || '';
  const clone = root?.cloneNode(true);
  if (clone) {
    clone.querySelectorAll?.('button, pre, code').forEach((el) => el.remove());
    return clone.textContent?.trim() || '';
  }
  return root?.textContent?.trim() || '';
}

function findPerplexityScrollContainer() {
  const strategies = [
    () => document.querySelector('.max-w-threadContentWidth, [class*="threadContentWidth"]'),
    () => document.querySelector('main'),
    () => {
      const first = document.querySelector('button[aria-label="Copy query"], button[data-testid="copy-query-button"], .prose');
      return first ? findScrollableAncestor(first) : null;
    },
    () => document.scrollingElement || document.documentElement,
  ];

  for (const strategy of strategies) {
    const result = strategy();
    if (result) return result;
  }
  return null;
}


// --- src/heuristics/pass1.js ---
// =============================================================================
// Chat Archive — Pass 1: Structural Heuristics
// =============================================================================
// Classifies turns using rule-based pattern detection when Pass 0
// (button extraction) didn't produce confident role assignments.
//
// Heuristic rules are ordered by confidence:
//   H1: Explicit role attributes (0.95)
//   H2: Alternating binary pattern (0.85)
//   H3: Asymmetric text length (0.70)
//   H4: Background color differentiation (0.75)
//   H5: Alignment pattern (0.80)
//   H6: Avatar/icon presence (0.70)
//   H7: Code block density (0.60)
//
// Combined confidence = weighted average of all firing rules.
// Threshold: 0.75 — accept classification if combined >= 0.75

const HEURISTIC_THRESHOLD = 0.75;

/**
 * Run heuristic classification on an array of extracted turns.
 * Turns that already have confidence >= threshold are left untouched.
 * Turns with lower confidence (or no role) get heuristic analysis.
 *
 * @param {Array} turns - Array of turn objects from extractors
 * @returns {Array} Same array with updated role/confidence/classificationSource
 */
function applyHeuristics(turns) {
  if (turns.length === 0) return turns;

  // Collect turns that need classification
  const needsClassification = [];
  for (let i = 0; i < turns.length; i++) {
    if (!turns[i].role || (turns[i].confidence || 0) < HEURISTIC_THRESHOLD) {
      needsClassification.push(i);
    }
  }

  if (needsClassification.length === 0) {
    console.log('[Chat Archive] Heuristics: All turns already classified at high confidence');
    return turns;
  }

  console.log(`[Chat Archive] Heuristics: ${needsClassification.length} turns need classification`);

  // Run each heuristic rule across the full conversation for context
  const results = turns.map((turn, index) => ({
    index,
    scores: { user: 0, assistant: 0 },
    rulesApplied: [],
    totalWeight: 0,
  }));

  // H1: Explicit role attributes (already handled by extractors, but double-check)
  applyH1ExplicitRoles(turns, results);

  // H2: Alternating binary pattern
  applyH2AlternatingPattern(turns, results);

  // H3: Asymmetric text length
  applyH3TextLength(turns, results);

  // H4: Background color / styling differentiation (requires DOM — use cached data)
  // (Skipped in post-extraction heuristics — this runs on already-extracted text)

  // H5: Content-based alignment signals (encoded in content or metadata)
  applyH5ContentSignals(turns, results);

  // H7: Code block density
  applyH7CodeBlocks(turns, results);

  // Apply results to turns that need classification
  for (const idx of needsClassification) {
    const result = results[idx];
    if (result.totalWeight === 0) continue;

    const userScore = result.scores.user / result.totalWeight;
    const assistantScore = result.scores.assistant / result.totalWeight;
    const confidence = Math.max(userScore, assistantScore);
    const role = userScore > assistantScore ? 'user' : 'assistant';

    if (confidence >= HEURISTIC_THRESHOLD) {
      turns[idx].role = role;
      turns[idx].confidence = parseFloat(confidence.toFixed(3));
      turns[idx].classificationSource = 'heuristic';
      turns[idx].heuristicRules = result.rulesApplied;
    } else {
      // Mark as uncertain for User Resolution UI
      turns[idx].confidence = parseFloat(confidence.toFixed(3));
      turns[idx].classificationSource = 'heuristic-uncertain';
      turns[idx].heuristicRules = result.rulesApplied;
      turns[idx].needsUserResolution = true;
    }
  }

  const resolved = needsClassification.filter(
    (i) => turns[i].confidence >= HEURISTIC_THRESHOLD && turns[i].role
  ).length;
  console.log(`[Chat Archive] Heuristics: Resolved ${resolved}/${needsClassification.length} turns`);

  return turns;
}

// --- Individual Heuristic Rules ---

/**
 * H1: Explicit role attributes in content or metadata.
 * Confidence: 0.95. Weight: 3.
 */
function applyH1ExplicitRoles(turns, results) {
  for (let i = 0; i < turns.length; i++) {
    const turn = turns[i];

    // Already classified with high confidence from extractor
    if (turn.role && (turn.confidence || 0) >= 0.90) {
      const target = turn.role === 'user' ? 'user' : 'assistant';
      results[i].scores[target] += 3 * 0.95;
      results[i].totalWeight += 3;
      results[i].rulesApplied.push('H1-explicit');
    }
  }
}

/**
 * H2: Alternating binary pattern.
 * If we have high-confidence turns at known positions, the turns between them
 * should alternate. Confidence: 0.85. Weight: 2.
 */
function applyH2AlternatingPattern(turns, results) {
  // Find anchor points (turns with high confidence)
  const anchors = [];
  for (let i = 0; i < turns.length; i++) {
    if (turns[i].role && (turns[i].confidence || 0) >= 0.90) {
      anchors.push({ index: i, role: turns[i].role });
    }
  }

  if (anchors.length === 0) {
    // No anchors — assume first turn is user (most conversations start this way)
    for (let i = 0; i < turns.length; i++) {
      const expectedRole = i % 2 === 0 ? 'user' : 'assistant';
      results[i].scores[expectedRole] += 2 * 0.85;
      results[i].totalWeight += 2;
      results[i].rulesApplied.push('H2-alternation-noanchor');
    }
    return;
  }

  // Propagate from anchors
  for (let i = 0; i < turns.length; i++) {
    // Find nearest anchor
    let nearest = anchors[0];
    let minDist = Math.abs(i - nearest.index);
    for (const anchor of anchors) {
      const dist = Math.abs(i - anchor.index);
      if (dist < minDist) {
        minDist = dist;
        nearest = anchor;
      }
    }

    // Expected role based on distance from anchor (alternating)
    const offset = i - nearest.index;
    const anchorIsUser = nearest.role === 'user';
    const expectedRole = (offset % 2 === 0) === anchorIsUser ? 'user' : 'assistant';

    // Confidence decreases with distance from anchor
    const distancePenalty = Math.max(0, 1 - minDist * 0.05);
    const weight = 2 * distancePenalty;

    results[i].scores[expectedRole] += weight * 0.85;
    results[i].totalWeight += weight;
    results[i].rulesApplied.push('H2-alternation');
  }
}

/**
 * H3: Asymmetric text length.
 * User messages tend to be shorter than assistant responses.
 * Confidence: 0.70. Weight: 1.
 */
function applyH3TextLength(turns, results) {
  if (turns.length < 2) return;

  // Calculate median text length
  const lengths = turns.map((t) => (t.content || '').length);
  const sorted = [...lengths].sort((a, b) => a - b);
  const median = sorted[Math.floor(sorted.length / 2)];

  if (median === 0) return;

  for (let i = 0; i < turns.length; i++) {
    const len = lengths[i];
    const ratio = len / median;

    // Short messages are more likely user turns
    if (ratio < 0.5) {
      results[i].scores.user += 1 * 0.70;
      results[i].totalWeight += 1;
      results[i].rulesApplied.push('H3-short');
    } else if (ratio > 2.0) {
      results[i].scores.assistant += 1 * 0.70;
      results[i].totalWeight += 1;
      results[i].rulesApplied.push('H3-long');
    }
    // Near-median: no signal
  }
}

/**
 * H5: Content-based signals.
 * Assistant messages tend to contain markdown formatting, lists, code blocks.
 * User messages tend to be questions or short directives.
 * Confidence: 0.65. Weight: 1.
 */
function applyH5ContentSignals(turns, results) {
  for (let i = 0; i < turns.length; i++) {
    const text = turns[i].content || '';

    // Assistant signals
    let assistantSignals = 0;
    if (text.includes('```')) assistantSignals += 2;          // Code fences
    if (/^\s*[-*]\s/m.test(text)) assistantSignals += 1;     // Bullet lists
    if (/^\s*\d+\.\s/m.test(text)) assistantSignals += 1;   // Numbered lists
    if (/^#{1,3}\s/m.test(text)) assistantSignals += 1;      // Markdown headings
    if (text.length > 500) assistantSignals += 1;             // Long content

    // User signals
    let userSignals = 0;
    if (text.endsWith('?')) userSignals += 2;                 // Questions
    if (text.length < 100) userSignals += 1;                  // Short
    if (/^(can you|please|help|what|how|why|when|where|who|is|are|do|does)/i.test(text)) {
      userSignals += 1;                                       // Question starters
    }

    if (assistantSignals > userSignals) {
      results[i].scores.assistant += 1 * 0.65;
      results[i].totalWeight += 1;
      results[i].rulesApplied.push('H5-content-assistant');
    } else if (userSignals > assistantSignals) {
      results[i].scores.user += 1 * 0.65;
      results[i].totalWeight += 1;
      results[i].rulesApplied.push('H5-content-user');
    }
  }
}

/**
 * H7: Code block density.
 * Messages with code blocks are almost always assistant turns.
 * Confidence: 0.60 (lower because users sometimes paste code too).
 * Weight: 1.
 */
function applyH7CodeBlocks(turns, results) {
  for (let i = 0; i < turns.length; i++) {
    const text = turns[i].content || '';
    const codeBlocks = (text.match(/```/g) || []).length / 2;

    if (codeBlocks >= 1) {
      results[i].scores.assistant += 1 * 0.60;
      results[i].totalWeight += 1;
      results[i].rulesApplied.push('H7-codeblocks');
    }
  }
}

/**
 * Post-heuristic integrity: verify the overall conversation makes sense.
 * Returns an array of warning strings.
 */
function heuristicIntegrityCheck(turns) {
  const warnings = [];

  // Check that we have at least some role diversity
  const roles = new Set(turns.map((t) => t.role).filter(Boolean));
  if (roles.size < 2 && turns.length > 1) {
    warnings.push('All turns classified as the same role; heuristics may have failed');
  }

  // Check for runs of same role > 3
  let maxRun = 0;
  let currentRun = 1;
  for (let i = 1; i < turns.length; i++) {
    if (turns[i].role === turns[i - 1].role) {
      currentRun++;
      maxRun = Math.max(maxRun, currentRun);
    } else {
      currentRun = 1;
    }
  }
  if (maxRun > 3) {
    warnings.push(`${maxRun} consecutive turns with the same role detected`);
  }

  // Count uncertain turns
  const uncertain = turns.filter((t) => t.needsUserResolution).length;
  if (uncertain > 0) {
    warnings.push(`${uncertain} turn(s) could not be confidently classified`);
  }

  return warnings;
}

/**
 * True when timestamp UI text clearly includes a calendar year. Without this, Date.parse maps
 * month+day-only strings (e.g. "Jan 4", "Apr 3") to year 2001 in Chrome/V8 — wrong for 2026 chats.
 */
function uiTimestampTextHasParsableYear(t) {
  if (/\d{4}/.test(t)) return true;
  // Numeric dates: 1/4/26, 04-01-2026, 4.1.26 (year is last or ISO year-first handled above)
  if (/\d{1,2}[./-]\d{1,2}[./-]\d{2,4}/.test(t)) return true;
  if (/\d{4}[./-]\d{1,2}[./-]\d{1,2}/.test(t)) return true;
  return false;
}

/**
 * Parse UI/thread timestamp text or ISO datetime into local-calendar YYYY-MM-DD for filenames.
 */
function parseUiTimestampToYyyyMmDd(raw) {
  if (raw == null) return null;
  if (typeof raw === 'number' && Number.isFinite(raw)) {
    return exportDateLocalYyyyMmDd(new Date(raw));
  }
  if (typeof raw !== 'string') return null;
  const t = raw.trim();
  if (!t) return null;
  if (/^\d{4}-\d{2}-\d{2}/.test(t)) {
    const ymd = t.slice(0, 10);
    if (/^\d{4}-\d{2}-\d{2}$/.test(ymd)) return ymd;
  }
  const ms = Date.parse(t);
  if (Number.isNaN(ms)) return null;
  if (!uiTimestampTextHasParsableYear(t)) return null;
  return exportDateLocalYyyyMmDd(new Date(ms));
}

/** Best-effort chat start date from first user turn that carries a parseable timestamp. */
function inferChatStartedYyyyMmDdFromTurns(turns) {
  if (!Array.isArray(turns) || turns.length === 0) return null;
  for (let i = 0; i < turns.length; i++) {
    if (turns[i].role !== 'user') continue;
    const y = parseUiTimestampToYyyyMmDd(turns[i].timestamp);
    if (y) return y;
  }
  return null;
}

/** DOM fallback when turn objects lack timestamps (e.g. partial extract). */
function inferChatStartedYyyyMmDdFromDom(platform) {
  if (platform === 'chatgpt') {
    const first = document.querySelector('[data-message-author-role="user"]');
    if (first) {
      const timeEl = first.querySelector('time[datetime]');
      if (timeEl) {
        const y = parseUiTimestampToYyyyMmDd(timeEl.getAttribute('datetime'));
        if (y) return y;
      }
    }
  }
  if (platform === 'claude') {
    const first = document.querySelector('[data-testid="user-message"]')
      || document.querySelector('.font-user-message');
    if (first) {
      const pair = first.closest('[data-test-render-count]') || first.closest('.grid') || document.body;
      const timeEl = first.querySelector('time[datetime]')
        || (pair && pair.querySelector('time[datetime]'));
      if (timeEl) {
        const y = parseUiTimestampToYyyyMmDd(timeEl.getAttribute('datetime'));
        if (y) return y;
      }
    }
  }
  return null;
}

function resolveChatStartedYyyyMmDdForExport(platform, turns) {
  return inferChatStartedYyyyMmDdFromTurns(turns) || inferChatStartedYyyyMmDdFromDom(platform) || null;
}


// --- src/utils/serializer.js ---
// =============================================================================
// Chat Archive — Serializer (JSON + Markdown)
// =============================================================================
// Transforms extracted turns into durable export formats.
// JSON is the canonical format. Markdown is the human-readable format.
// Both are addressable artifacts — they have destinations beyond the export.

/**
 * Serialize extracted turns into the canonical JSON export format.
 */
function serializeToJSON(extraction, platform) {
  const integrityWarnings = runIntegrityChecks(extraction.turns);
  const exportInstant = new Date();
  const chatStartedYyyyMmDdMeta = resolveChatStartedYyyyMmDdForExport(platform, extraction.turns);

  const exportData = {
    schema_version: SCHEMA_VERSION,
    export_metadata: {
      source_platform: platformToDisplayName(platform),
      source_url: window.location.href,
      export_timestamp: exportTimestampIsoOffset(exportInstant),
      chat_started_yyyy_mm_dd: chatStartedYyyyMmDdMeta,
      extension_version: EXTENSION_VERSION,
      total_turns: extraction.turns.length,
      flagged_turns: extraction.turns.filter((t) => t.flagged).length,
      partial_export: extraction.partial || false,
      extraction_errors: extraction.errors || [],
      integrity_warnings: integrityWarnings,
    },
    conversation: extraction.turns.map((turn, index) => {
      const entry = {
        turn: index + 1,
        role: turn.role || 'unknown',
        content: turn.content,
        classification_confidence: turn.confidence || null,
        classification_source: turn.classificationSource || 'unknown',
      };

      // Optional fields
      if (turn.timestamp) entry.timestamp = turn.timestamp;
      if (turn.flagged) {
        entry.flagged = true;
        entry.flag_reason = turn.flagReason;
      }
      if (turn.extractionMethod) entry.extraction_method = turn.extractionMethod;
      if (turn.turnId) entry.turn_id = turn.turnId;
      if (turn.modelSlug) entry.model = turn.modelSlug;
      if (turn.needsUserResolution) entry.needs_user_resolution = true;

      return entry;
    }),
  };

  return {
    json: JSON.stringify(exportData, null, 2),
    metadata: exportData.export_metadata,
    integrityWarnings,
  };
}

/**
 * Serialize extracted turns into Markdown format.
 */
function serializeToMarkdown(extraction, platform) {
  const integrityWarnings = runIntegrityChecks(extraction.turns);

  const platformName = platformToDisplayName(platform);
  const exportInstant = new Date();
  const timestamp = exportTimestampDisplay(exportInstant);
  const sourceUrl = window.location.href;

  const lines = [];

  // --- Header ---
  lines.push(`# Chat Export — ${platformName}`);
  lines.push(`**Exported:** ${timestamp}  `);
  lines.push(`**Source:** ${sourceUrl}  `);
  lines.push(`**Turns:** ${extraction.turns.length}`);

  if (extraction.partial) {
    lines.push(`**Status:** Partial export (${extraction.errors.length} errors)`);
  }

  lines.push('');
  lines.push('---');
  lines.push('');

  // --- Turns ---
  for (let i = 0; i < extraction.turns.length; i++) {
    const turn = extraction.turns[i];
    const role = turn.role || 'Unknown';
    const roleLabel = role.charAt(0).toUpperCase() + role.slice(1);

    lines.push(`## ${roleLabel}`);

    if (turn.timestamp) {
      lines.push(`*${turn.timestamp}*`);
      lines.push('');
    }

    // Content: preserve as-is (clipboard extraction gives us markdown already)
    lines.push(turn.content || '*(empty)*');

    if (turn.flagged) {
      lines.push('');
      lines.push(`> ⚠️ ${turn.flagReason || 'Flagged'}`);
    }

    if (turn.needsUserResolution) {
      lines.push('');
      lines.push('> ⚠️ Role classification uncertain; may need manual correction');
    }

    lines.push('');
    lines.push('---');
    lines.push('');
  }

  // --- Footer ---
  if (integrityWarnings.length > 0) {
    lines.push('## Export Notes');
    lines.push('');
    for (const warning of integrityWarnings) {
      lines.push(`- ${warning}`);
    }
    lines.push('');
  }

  lines.push(`*Exported by Chat Archive v${EXTENSION_VERSION}*`);

  return {
    markdown: lines.join('\n'),
    metadata: {
      source_platform: platformName,
      source_url: sourceUrl,
      export_timestamp: exportTimestampIsoOffset(exportInstant),
      extension_version: EXTENSION_VERSION,
      total_turns: extraction.turns.length,
      flagged_turns: extraction.turns.filter((t) => t.flagged).length,
      partial_export: extraction.partial || false,
    },
    integrityWarnings,
  };
}

/** SDOC: backslash-escape special characters (aligned with vscode-sdoc parser ESCAPABLE). */
function escapeSdocText(text) {
  const esc = '\\{}@[]()*`#!~<>$+=-^?|';
  const set = new Set(esc.split(''));
  let out = '';
  for (const ch of text) {
    if (set.has(ch)) out += '\\';
    out += ch;
  }
  return out;
}

function escapeSdocMetaValue(value) {
  return escapeSdocText(String(value).replace(/\r?\n/g, ' '));
}

/** Escape prose for SDOC scopes; leave fenced ``` code blocks unescaped so braces inside code stay valid. */
function escapeSdocSegment(text) {
  if (text == null || text === '') return '';
  const parts = String(text).split(/(```[\s\S]*?```)/g);
  return parts.map((part) => (part.startsWith('```') ? part : escapeSdocText(part))).join('');
}

function sdocCapitalizeRole(role) {
  const r = role || 'unknown';
  return r.charAt(0).toUpperCase() + r.slice(1);
}

/**
 * Serialize extracted turns into SDOC (brace-scoped, agent-friendly).
 * @see https://github.com/nathanspear/sdoc
 */
function serializeToSdoc(extraction, platform, chatTitle, chatId) {
  const integrityWarnings = runIntegrityChecks(extraction.turns);
  const headingTitle = escapeSdocText(
    (chatTitle || '').replace(/\s+/g, ' ').trim() || 'Chat'
  );
  const idSlug = String(chatId || 'chat').replace(/[^a-zA-Z0-9_-]/g, '-') || 'chat';
  const rootSlug = `chat-${idSlug}`;
  const platformName = platformToDisplayName(platform);
  const sourceUrl = window.location.href;
  const exportInstant = new Date();
  const ts = exportTimestampIsoOffset(exportInstant);

  const metaLines = [
    `        id: ${escapeSdocMetaValue(idSlug)}`,
    `        title: ${escapeSdocMetaValue(chatTitle || 'Chat')}`,
    `        source_platform: ${escapeSdocMetaValue(platformName)}`,
    `        source_url: ${escapeSdocMetaValue(sourceUrl)}`,
    `        export_timestamp: ${escapeSdocMetaValue(ts)}`,
    `        total_turns: ${extraction.turns.length}`,
    `        partial_export: ${extraction.partial ? 'true' : 'false'}`,
  ];

  const messageBlocks = extraction.turns
    .map((turn, i) => {
      const role = sdocCapitalizeRole(turn.role || 'unknown');
      const slug = `turn-${i + 1}-${turn.role || 'unknown'}`;
      const raw = turn.content && String(turn.content).trim().length ? turn.content : '*(empty)*';
      const body = escapeSdocSegment(raw);
      const lines = [`    # ${role} @${slug}`, '    {'];
      if (body) {
        for (const line of body.split('\n')) {
          lines.push(line.length ? `        ${line}` : '');
        }
      }
      lines.push('    }');
      return lines.join('\n');
    })
    .join('\n\n');

  const doc = [
    `# ${headingTitle} @${rootSlug}`,
    '{',
    '    # Meta @meta',
    '    {',
    metaLines.join('\n'),
    '    }',
    '',
    '    # Conversation @conversation',
    '    {',
    messageBlocks,
    '    }',
    '}',
    '',
  ].join('\n');

  return {
    sdoc: doc,
    metadata: {
      source_platform: platformName,
      source_url: sourceUrl,
      export_timestamp: ts,
      extension_version: EXTENSION_VERSION,
      total_turns: extraction.turns.length,
      flagged_turns: extraction.turns.filter((t) => t.flagged).length,
      partial_export: extraction.partial || false,
    },
    integrityWarnings,
  };
}

function resolveExportFlags(options) {
  if (
    options.includeMarkdown !== undefined ||
    options.includeJson !== undefined ||
    options.includeSdoc !== undefined
  ) {
    return {
      includeMarkdown: options.includeMarkdown === true,
      includeJson: options.includeJson === true,
      includeSdoc: options.includeSdoc === true,
    };
  }
  const f = options.format || 'markdown';
  return {
    includeMarkdown: f === 'markdown' || f === 'both',
    includeJson: f === 'json' || f === 'both',
    includeSdoc: false,
  };
}

/**
 * Run integrity checks on extracted turns before serialization.
 */
function runIntegrityChecks(turns) {
  const warnings = [];

  if (turns.length === 0) {
    warnings.push('No turns extracted');
    return warnings;
  }

  // Check 1: Turn alternation pattern
  let alternationViolations = 0;
  for (let i = 1; i < turns.length; i++) {
    if (turns[i].role === turns[i - 1].role) {
      alternationViolations++;
    }
  }
  if (alternationViolations > 0) {
    warnings.push(
      `${alternationViolations} consecutive same-role turn(s) detected. ` +
      'This may indicate missed turns or system messages.'
    );
  }

  // Check 2: Consecutive duplicate content
  for (let i = 1; i < turns.length; i++) {
    if (turns[i].content === turns[i - 1].content && turns[i].content.length > 0) {
      warnings.push(`Duplicate content detected between turns ${i} and ${i + 1}`);
    }
  }

  // Check 3: Suspiciously large turns
  const largeTurns = turns.filter((t) => t.content.length > SAFETY_LIMITS.MAX_SINGLE_TURN_SIZE);
  if (largeTurns.length > 0) {
    warnings.push(`${largeTurns.length} turn(s) exceed 100KB`);
  }

  // Check 4: Empty turns
  const emptyTurns = turns.filter((t) => !t.content || t.content.trim().length === 0);
  if (emptyTurns.length > 0) {
    warnings.push(`${emptyTurns.length} empty turn(s) detected`);
  }

  // Check 5: Unresolved roles
  const unknownRoles = turns.filter((t) => !t.role || t.role === 'unknown');
  if (unknownRoles.length > 0) {
    warnings.push(`${unknownRoles.length} turn(s) with unknown roles`);
  }

  return warnings;
}


// --- src/utils/filewriter.js ---
// =============================================================================
// Chat Archive — File Writer
// =============================================================================
// Writes serialized output to user's device via Chrome downloads API.
// Phase 2: JSON + Markdown.
// slugForExport and buildExportFilename are loaded from filename-builder.js (listed first in manifest content_scripts).

/**
 * Download content as a file using the Chrome downloads API via background.js.
 */
function downloadViaBackground(content, filename, mimeType) {
  return new Promise((resolve, reject) => {
    chrome.runtime.sendMessage(
      {
        action: 'download',
        content,
        filename,
        mimeType,
      },
      (response) => {
        if (chrome.runtime.lastError) {
          reject(new Error(chrome.runtime.lastError.message));
        } else if (response && response.success) {
          resolve(response);
        } else {
          reject(new Error(response?.error || 'Download failed'));
        }
      }
    );
  });
}

/**
 * Fallback: Download via Blob URL and <a> click.
 */
function downloadViaBlob(content, filename, mimeType) {
  const blob = new Blob([content], { type: mimeType });
  const url = URL.createObjectURL(blob);
  const a = document.createElement('a');
  a.href = url;
  a.download = filename;
  document.body.appendChild(a);
  a.click();
  document.body.removeChild(a);
  URL.revokeObjectURL(url);
}

/**
 * Download a file. Background uses a data URL for smaller payloads so it works after worker sleep.
 */
async function downloadFile(content, filename, mimeType) {
  try {
    await downloadViaBackground(content, filename, mimeType);
    return;
  } catch (err) {
    console.warn('[Chat Archive] Background download failed, trying in-page blob:', err.message);
    downloadViaBlob(content, filename, mimeType);
  }
}

/** Bundle multiple export parts into one .zip (single-chat + "Create ZIP" enabled). */
function downloadZipViaBackground(folderName, files) {
  return new Promise((resolve, reject) => {
    chrome.runtime.sendMessage(
      { action: 'downloadZip', folderName, files, zipJsZipDateMs: msForJsZipDosLocalMtime() },
      (response) => {
        if (chrome.runtime.lastError) {
          reject(new Error(chrome.runtime.lastError.message));
        } else if (response && response.success) {
          resolve(response);
        } else {
          reject(new Error(response?.error || 'ZIP download failed'));
        }
      }
    );
  });
}


// --- src/content.js ---
// =============================================================================
// Chat Archive — Content Script (Orchestrator)
// =============================================================================
// Injected into AI chat platform pages. Orchestrates:
//   Pass 0: Platform-specific button extraction (clipboard)
//   Pass 1: Structural heuristics (fallback for uncertain turns)
//   Serialization: JSON + Markdown
//   Download: via Chrome API or blob fallback

// =============================================================================
// Project & Chat Discovery (ChatGPT)
// =============================================================================

function discoverChatGPTProjects() {
  const projects = [];
  
  const sidebar = document.querySelector('aside, nav[aria-label*="sidebar" i], div[class*="sidebar"]');
  if (!sidebar) {
    return { error: 'Sidebar not found', projects: [] };
  }

  const projectElements = sidebar.querySelectorAll('a[href*="/p/"], a[href*="/project/"]');
  
  for (const elem of projectElements) {
    const href = elem.getAttribute('href');
    if (!href) continue;
    
    const match = href.match(/\/p\/([^\/]+)/);
    if (!match) continue;
    
    const projectId = match[1];
    const projectName = elem.textContent?.trim() || `Project ${projectId}`;
    
    projects.push({
      id: projectId,
      name: projectName,
      url: href.startsWith('http') ? href : `https://chatgpt.com${href}`,
    });
  }
  
  return { projects };
}

async function discoverChatGPTChatsInCurrentProject() {
  const chats = [];
  const seenIds = new Set();

  function getChatTitleFromLink(link) {
    const aria = link.getAttribute('aria-label')?.trim();
    if (aria) return aria;
    const titleEl = link.querySelector('[class*="title" i], [class*="heading" i], strong, b');
    if (titleEl) {
      const t = titleEl.textContent?.trim();
      if (t) return t;
    }
    const full = link.textContent?.trim() || '';
    const firstLine = full.split(/\n/)[0]?.trim();
    if (firstLine) return firstLine;
    return full || null;
  }

  function addChat(link) {
    const href = link.getAttribute('href');
    if (!href) return;
    const match = href.match(/\/c\/([^\/\?]+)/);
    if (!match) return;
    const chatId = match[1];
    if (seenIds.has(chatId)) return;
    seenIds.add(chatId);
    const title = getChatTitleFromLink(link) || link.textContent?.trim() || `Chat ${chatId}`;
    chats.push({
      id: chatId,
      title,
      url: href.startsWith('http') ? href : `https://chatgpt.com${href}`,
    });
  }

  function isInsideLeftNav(link) {
    for (const root of leftNavRoots) {
      if (root.contains(link)) return true;
    }
    return false;
  }

  const isProjectPage = /\/g\/[^/]+\/project/.test(window.location.href) || /\/p\/[^/]+/.test(window.location.href);

  // All possible left-nav roots: sidebars, asides, navs (projects list + chats below are often in these).
  const leftNavRoots = [
    ...document.querySelectorAll('aside'),
    ...document.querySelectorAll('nav'),
    ...document.querySelectorAll('[class*="sidebar" i]'),
    ...document.querySelectorAll('[data-testid*="sidebar" i]'),
    ...document.querySelectorAll('[data-testid*="side-bar" i]'),
    ...document.querySelectorAll('[aria-label*="sidebar" i]'),
  ].filter((el) => el && el.isConnected);

  if (isProjectPage) {
    // Project is selected: only list chats in the main content. Exclude anything in left nav (all asides/navs/sidebars).
    const allChatLinks = document.querySelectorAll('a[href*="/c/"]');
    for (const link of allChatLinks) {
      if (isInsideLeftNav(link)) continue;
      addChat(link);
    }
  } else {
    // No project selected: scroll Recents list to load all lazy-rendered chat links, then discover.
    await scrollRecentsListToLoadAll('a[href*="/c/"]');
    for (const root of leftNavRoots) {
      root.querySelectorAll('a[href*="/c/"]').forEach(addChat);
    }
  }

  return { chats };
}

/**
 * Get the current ChatGPT project ID (if any) from the URL.
 * Returns { id } only — name is user-supplied, not inferred.
 */
function getCurrentChatGPTProject() {
  const url = window.location.href;
  const pMatch = url.match(/\/p\/([^\/]+)/);
  if (pMatch) return { id: pMatch[1], name: null };
  const gMatch = url.match(/\/g\/([^\/]+)\/project/);
  if (gMatch) return { id: gMatch[1], name: null };
  return null;
}

// ============================================================================
// Recents List Scroll Helper
// ============================================================================

/**
 * Scroll the Recents sidebar list to the bottom so all lazy-loaded chat links
 * are rendered in the DOM before discovery runs.
 *
 * Strategy: find the scrollable container inside the left nav that holds chat
 * links, then scroll it downward in steps (same pattern as scrollToLoadAll)
 * until the chat-link count stabilises across 3 consecutive iterations.
 *
 * @param {string} chatLinkSelector  CSS selector that matches chat links in the sidebar
 * @returns {Promise<number>}  Number of scroll iterations performed
 */
async function scrollRecentsListToLoadAll(chatLinkSelector) {
  // Find the scrollable sidebar container that holds the Recents list.
  // We walk up from the first matching chat link to find its scrollable ancestor
  // that lives inside a left-nav root (aside / nav / sidebar).
  const leftNavRoots = [
    ...document.querySelectorAll('aside'),
    ...document.querySelectorAll('nav'),
    ...document.querySelectorAll('[class*="sidebar" i]'),
    ...document.querySelectorAll('[data-testid*="sidebar" i]'),
    ...document.querySelectorAll('[data-testid*="side-bar" i]'),
    ...document.querySelectorAll('[aria-label*="sidebar" i]'),
  ].filter((el) => el && el.isConnected);

  // Find the first chat link that lives inside a left-nav root
  let scrollContainer = null;
  const allLinks = document.querySelectorAll(chatLinkSelector);
  for (const link of allLinks) {
    for (const root of leftNavRoots) {
      if (root.contains(link)) {
        // Walk up from the link to find the scrollable ancestor within this root
        const candidate = findScrollableAncestor(link);
        if (candidate && root.contains(candidate)) {
          scrollContainer = candidate;
        }
        break;
      }
    }
    if (scrollContainer) break;
  }

  // Fallback: try the left-nav roots themselves for overflow-y
  if (!scrollContainer) {
    for (const root of leftNavRoots) {
      const style = window.getComputedStyle(root);
      if (style.overflowY === 'scroll' || style.overflowY === 'auto') {
        scrollContainer = root;
        break;
      }
      // Check direct children
      for (const child of root.children) {
        const cs = window.getComputedStyle(child);
        if (cs.overflowY === 'scroll' || cs.overflowY === 'auto') {
          scrollContainer = child;
          break;
        }
      }
      if (scrollContainer) break;
    }
  }

  if (!scrollContainer) {
    console.log('[ChatVault] scrollRecentsListToLoadAll: no scrollable container found, skipping');
    return 0;
  }

  console.log('[ChatVault] scrollRecentsListToLoadAll: scrolling', scrollContainer.tagName, scrollContainer.className);

  const startTime = Date.now();
  let previousCount = 0;
  let stableIterations = 0;
  let scrollIterations = 0;

  // Start from the top so we don't miss anything
  scrollContainer.scrollTop = 0;
  await wait(300);

  while (
    stableIterations < SAFETY_LIMITS.SCROLL_STABILITY_THRESHOLD &&
    scrollIterations < SAFETY_LIMITS.MAX_SCROLL_ITERATIONS
  ) {
    if (Date.now() - startTime > 30_000) break; // 30 s safety cap

    const currentCount = scrollContainer.querySelectorAll(chatLinkSelector).length;
    if (currentCount === previousCount) {
      stableIterations++;
    } else {
      stableIterations = 0;
      previousCount = currentCount;
    }

    scrollContainer.scrollBy(0, scrollContainer.clientHeight * 0.8);
    await wait(SAFETY_LIMITS.SCROLL_STEP_DELAY_MS);
    scrollIterations++;
  }

  // Leave scroll position at bottom so newly rendered links stay in DOM
  console.log(`[ChatVault] scrollRecentsListToLoadAll: ${previousCount} links after ${scrollIterations} scrolls`);
  return scrollIterations;
}

